window.EA_CURRICULUM_INDEX = {"intro":[{"page":3,"unit":1,"topic":"Possessive Adjectives — My, Your, His, Her","ex":[{"en":"Hello. What's your name?","pt":"Olá. Qual é o seu nome?"},{"en":"Hi. My name is Carlos.","pt":"Oi. Meu nome é Carlos."},{"en":"What's his name? — His name is Joshua.","pt":"Qual é o nome dele? — O nome dele é Joshua."},{"en":"What's her name? — Her name is Isabella.","pt":"Qual é o nome dela? — O nome dela é Isabella."},{"en":"What's = What is","pt":"\"What's\" é a contração de \"what is\"."}]},{"page":5,"unit":1,"topic":"The Verb Be (Afirmativa)","ex":[{"en":"I'm Lena Garza.","pt":"Eu sou a Lena Garza."},{"en":"You're in my class.","pt":"Você está na minha turma."},{"en":"She's over there. Andrea is over there.","pt":"Ela está ali. A Andrea está ali."},{"en":"He's in our class. Ben is in our class.","pt":"Ele está na nossa turma. O Ben está na nossa turma."},{"en":"How are you? — I'm fine, thanks.","pt":"Como você está? — Estou bem, obrigado."}]},{"page":10,"unit":2,"topic":"This/These, It/They; Plurals","ex":[{"en":"This is a laptop. — What's this? It's a flash drive.","pt":"Isto é um laptop. — O que é isto? É um pen drive."},{"en":"These are laptops. — What are these? They're flash drives.","pt":"Estes são laptops. — O que são estes? São pen drives."},{"en":"What are these? — They're keys.","pt":"O que são estes? — São chaves."},{"en":"What's this? — It's an umbrella.","pt":"O que é isto? — É um guarda-chuva."},{"en":"What are these? — They're sunglasses.","pt":"O que são estes? — São óculos de sol."}]},{"page":11,"unit":2,"topic":"Yes/No and Where Questions with Be","ex":[{"en":"Is this your cell phone? — Yes, it is. / No, it's not.","pt":"Este é o seu celular? — Sim, é. / Não, não é."},{"en":"Are these your keys? — Yes, they are. / No, they're not.","pt":"Estas são as suas chaves? — Sim, são. / Não, não são."},{"en":"Where's my umbrella? — It's on your chair.","pt":"Onde está meu guarda-chuva? — Está na sua cadeira."},{"en":"Where are my glasses? — They're in your pocket.","pt":"Onde estão meus óculos? — Estão no seu bolso."},{"en":"Where are my headphones? — They're in my backpack.","pt":"Onde estão meus fones? — Estão na minha mochila."}]},{"page":17,"unit":3,"topic":"Negative Statements and Yes/No Questions with Be","ex":[{"en":"I'm not from Rio. I'm from São Paulo.","pt":"Não sou do Rio. Sou de São Paulo."},{"en":"She's not from Japan. She's from Korea.","pt":"Ela não é do Japão. Ela é da Coreia."},{"en":"Are Diana and Mario from Ecuador? — No, they're not. They're from Mexico.","pt":"A Diana e o Mario são do Equador? — Não, não são. Eles são do México."},{"en":"Is Meera from England? — No, she's not. She's from Australia.","pt":"A Meera é da Inglaterra? — Não, não é. Ela é da Austrália."},{"en":"Are you Egyptian? — No, it's not. It's Cantonese.","pt":"Você é egípcio? — Não. É cantonês."}]},{"page":20,"unit":3,"topic":"Wh-Questions with Be","ex":[{"en":"What's your name? — My name is Sophia.","pt":"Qual é o seu nome? — Meu nome é Sophia."},{"en":"Where are you from? — I'm from Canada.","pt":"De onde você é? — Sou do Canadá."},{"en":"How old is she? — She's twenty-eight.","pt":"Quantos anos ela tem? — Ela tem 28 anos."},{"en":"Who's that? — She's my sister.","pt":"Quem é aquela? — É a minha irmã."},{"en":"What's San Francisco like? — It's very beautiful.","pt":"Como é São Francisco? — É muito bonita."}]},{"page":24,"unit":4,"topic":"Possessives — Adjectives, Pronouns, and Names","ex":[{"en":"This isn't my raincoat. Is it yours?","pt":"Esta capa de chuva não é minha. É a sua?"},{"en":"These aren't our sneakers. They're Logan's.","pt":"Estes não são nossos tênis. São do Logan."},{"en":"Are these your gloves, Erin? — No, they're not mine.","pt":"Estas luvas são suas, Erin? — Não, não são minhas."},{"en":"Whose T-shirts are these? — They're Hayley and Brad's.","pt":"De quem são estas camisetas? — São da Hayley e do Brad."},{"en":"Taylor's shoes are over there.","pt":"Os sapatos da Taylor estão ali."}]},{"page":26,"unit":4,"topic":"Present Continuous Statements; Conjunctions","ex":[{"en":"My name is Dylan Jones. I'm wearing a new gray suit.","pt":"Meu nome é Dylan Jones. Estou usando um terno cinza novo."},{"en":"It's hot and sunny today. Michael is wearing shorts.","pt":"Está quente e ensolarado hoje. O Michael está usando shorts."},{"en":"Adriana is wearing a yellow dress and a brown belt.","pt":"A Adriana está usando um vestido amarelo e um cinto marrom."},{"en":"It's snowing, but it's not very cold.","pt":"Está nevando, mas não está muito frio."},{"en":"It's windy, so we're wearing heavy coats.","pt":"Está ventando, então estamos usando casacos pesados."}]},{"page":27,"unit":4,"topic":"Present Continuous Yes/No Questions; Adjective + Noun","ex":[{"en":"Is Dylan wearing a gray suit? — Yes, he is.","pt":"O Dylan está usando um terno cinza? — Sim, está."},{"en":"Is he wearing a raincoat? — No, he's not.","pt":"Ele está usando uma capa de chuva? — Não, não está."},{"en":"Are they wearing gloves and hats? — Yes, they are.","pt":"Eles estão usando luvas e chapéus? — Sim, estão."},{"en":"My suit is black. I'm wearing a black suit.","pt":"Meu terno é preto. Estou usando um terno preto."},{"en":"Is Bruno wearing a red shirt? — No, he isn't.","pt":"O Bruno está usando uma camisa vermelha? — Não, não está."}]},{"page":31,"unit":5,"topic":"What Time Is It? / A.M. and P.M.","ex":[{"en":"What time is it? — It's two o'clock.","pt":"Que horas são? — São duas horas."},{"en":"It's a quarter after two. (2:15)","pt":"São duas e quinze."},{"en":"It's twenty to three. (2:40)","pt":"São vinte para as três."},{"en":"It's eight o'clock in the morning. It's 8:00 a.m.","pt":"São oito horas da manhã."},{"en":"It's twelve o'clock at night. It's midnight.","pt":"É meia-noite."}]},{"page":37,"unit":6,"topic":"Simple Present Statements","ex":[{"en":"My family and I live in the suburbs.","pt":"Minha família e eu moramos nos subúrbios."},{"en":"My wife and I walk to work.","pt":"Minha esposa e eu vamos andando para o trabalho."},{"en":"Our daughter Megan works downtown.","pt":"Nossa filha Megan trabalha no centro."},{"en":"My son doesn't drive a car. He rides his bike to school.","pt":"Meu filho não dirige. Ele vai de bicicleta para a escola."},{"en":"My father doesn't work now. He's retired.","pt":"Meu pai não trabalha agora. Está aposentado."}]},{"page":38,"unit":6,"topic":"Simple Present with Irregular Verbs — Have, Do, Go","ex":[{"en":"I have a bike.","pt":"Eu tenho uma bicicleta."},{"en":"My mother has a car.","pt":"Minha mãe tem um carro."},{"en":"We do our homework every day.","pt":"Fazemos a lição todo dia."},{"en":"My father does a lot of work at home.","pt":"Meu pai faz muito trabalho em casa."},{"en":"My parents go to work by train. The train goes downtown.","pt":"Meus pais vão de trem para o trabalho. O trem vai para o centro."}]},{"page":39,"unit":6,"topic":"Simple Present Questions","ex":[{"en":"Do you get up early on Sundays? — No, I get up late.","pt":"Você acorda cedo aos domingos? — Não, acordo tarde."},{"en":"Does he eat breakfast at seven o'clock? — No, he eats breakfast at seven-thirty.","pt":"Ele toma café às sete? — Não, toma café às sete e meia."},{"en":"What time do you get up? — At noon.","pt":"Que horas você acorda? — Ao meio-dia."},{"en":"When do you take the subway? — On Mondays and Wednesdays.","pt":"Quando você pega o metrô? — Às segundas e quartas."},{"en":"What time does she have dinner? — At eight o'clock.","pt":"Que horas ela janta? — Às oito horas."}]},{"page":45,"unit":7,"topic":"Simple Present Short Answers","ex":[{"en":"Do you live in an apartment? — No, I don't. I live in a house.","pt":"Você mora num apartamento? — Não. Moro numa casa."},{"en":"Does it have a yard? — Yes, it does.","pt":"Ela tem um quintal? — Sim, tem."},{"en":"Do you live alone? — No, I don't. I live with my family.","pt":"Você mora sozinho? — Não. Moro com minha família."},{"en":"Do you have any brothers or sisters? — Yes, I do. I have four sisters.","pt":"Você tem irmãos? — Sim, tenho. Tenho quatro irmãs."},{"en":"Does your house have many bedrooms? — Yes, it does. It has four.","pt":"Sua casa tem muitos quartos? — Sim, tem. Tem quatro."}]},{"page":47,"unit":7,"topic":"There Is, There Are","ex":[{"en":"There's a bed in the bedroom.","pt":"Há uma cama no quarto."},{"en":"There are some chairs in the kitchen.","pt":"Há algumas cadeiras na cozinha."},{"en":"There's no sofa in the bedroom.","pt":"Não há sofá no quarto."},{"en":"There are no chairs in the living room.","pt":"Não há cadeiras na sala."},{"en":"There aren't any curtains on the windows.","pt":"Não há cortinas nas janelas."}]},{"page":52,"unit":8,"topic":"Simple Present Wh-Questions","ex":[{"en":"Where do you work? — In a hospital.","pt":"Onde você trabalha? — Em um hospital."},{"en":"What do you do? — I'm a doctor.","pt":"O que você faz? — Sou médico."},{"en":"What does he do? — He's a manager.","pt":"O que ele faz? — Ele é gerente."},{"en":"Where do they work? — In an office.","pt":"Onde eles trabalham? — Em um escritório."},{"en":"How does he like it? — It's OK.","pt":"Como ele acha o trabalho? — É legal."}]},{"page":54,"unit":8,"topic":"Placement of Adjectives","ex":[{"en":"A photographer's job is interesting. — A photographer has an interesting job.","pt":"O trabalho de fotógrafo é interessante. — Um fotógrafo tem um trabalho interessante."},{"en":"A pilot's job is exciting. — A pilot has an exciting job.","pt":"O trabalho de piloto é empolgante."},{"en":"A teacher's job is stressful. — A teacher has a stressful job.","pt":"O trabalho de professor é estressante."},{"en":"A cashier has a boring job.","pt":"Um caixa tem um trabalho chato."},{"en":"A receptionist has an easy job.","pt":"Um recepcionista tem um trabalho fácil."}]},{"page":59,"unit":9,"topic":"Count and Noncount Nouns; Some and Any","ex":[{"en":"Do we need any potatoes? — Yes. Let's get some potatoes.","pt":"Precisamos de batatas? — Sim. Vamos comprar algumas batatas."},{"en":"Do we need any lettuce? — No. We don't need any lettuce.","pt":"Precisamos de alface? — Não. Não precisamos de alface."},{"en":"Let's get some cheese. And some chicken, too.","pt":"Vamos comprar queijo. E frango também."},{"en":"We don't have any bread. We need some.","pt":"Não temos pão. Precisamos comprar."},{"en":"Do you want some mayonnaise? — No, I don't want any.","pt":"Você quer maionese? — Não, não quero."}]},{"page":61,"unit":9,"topic":"Adverbs of Frequency","ex":[{"en":"I always eat breakfast.","pt":"Sempre tomo café da manhã."},{"en":"I usually have a big breakfast with my friends.","pt":"Geralmente tomo um grande café com meus amigos."},{"en":"I sometimes eat at my desk.","pt":"Às vezes como na minha mesa."},{"en":"Do you ever have fish for breakfast? — Yes, I always do.","pt":"Você costuma comer peixe no café? — Sim, sempre."},{"en":"I hardly ever have beef for lunch.","pt":"Quase nunca como carne no almoço."}]},{"page":65,"unit":10,"topic":"Simple Present Wh-Questions — Sports and Free Time","ex":[{"en":"What sports do you play? — I play soccer and basketball.","pt":"Que esportes você pratica? — Eu jogo futebol e basquete."},{"en":"Who do you play basketball with? — I play with some friends from work.","pt":"Com quem você joga basquete? — Eu jogo com uns amigos do trabalho."},{"en":"Where do you play? — We play at a gym near the office.","pt":"Onde vocês jogam? — Jogamos numa academia perto do escritório."},{"en":"How often do you practice? — We practice twice a week.","pt":"Com que frequência você treina? — Treinamos duas vezes por semana."},{"en":"What time do you start? — We start at six in the evening.","pt":"A que horas vocês começam? — Começamos às seis da noite."}]},{"page":67,"unit":10,"topic":"Can for Ability","ex":[{"en":"I can swim.","pt":"Eu sei nadar."},{"en":"I can't fix cars.","pt":"Eu não sei consertar carros."},{"en":"Lisa can play the piano.","pt":"A Lisa sabe tocar piano."},{"en":"Can Ben swim? — Yes, he can.","pt":"O Ben sabe nadar? — Sim, sabe."},{"en":"What can Diane do? — She can sing.","pt":"O que a Diane sabe fazer? — Ela sabe cantar."}]},{"page":73,"unit":11,"topic":"The Future with Be Going to","ex":[{"en":"Are you going to do anything this weekend? — Yes, I am. I'm going to celebrate my birthday.","pt":"Você vai fazer alguma coisa neste fim de semana? — Sim. Vou comemorar meu aniversário."},{"en":"Is Rosa going to cook dinner for you? — Yes, she is. She's going to cook a special dinner.","pt":"A Rosa vai fazer o jantar para você? — Sim. Ela vai fazer um jantar especial."},{"en":"Are your friends going to be there? — Yes, they are. They're going to stop by after dinner.","pt":"Seus amigos vão estar lá? — Sim. Eles vão passar lá depois do jantar."},{"en":"I'm not going to stay home this weekend.","pt":"Não vou ficar em casa neste fim de semana."},{"en":"She's going to order takeout tonight.","pt":"Ela vai pedir comida hoje à noite."}]},{"page":75,"unit":11,"topic":"Wh-Questions with Be Going to","ex":[{"en":"What are you going to do for Valentine's Day? — I'm going to go to a dance club.","pt":"O que você vai fazer no Dia dos Namorados? — Vou para uma boate."},{"en":"How is Allie going to get to the dance club? — She's going to drive.","pt":"Como a Allie vai chegar à boate? — Ela vai dirigir."},{"en":"Where are Jim and his girlfriend going to eat? — They're going to eat at the Red Rose.","pt":"Onde o Jim e a namorada vão comer? — Eles vão comer no Red Rose."},{"en":"Who are you going to spend Thanksgiving with? — My parents and I are going to visit my grandparents.","pt":"Com quem você vai passar o feriado? — Meus pais e eu vamos visitar meus avós."},{"en":"What is she going to do for New Year's Day? — I don't know. She's not going to do anything special.","pt":"O que ela vai fazer no Ano Novo? — Não sei. Ela não vai fazer nada de especial."}]},{"page":79,"unit":12,"topic":"Have + Noun; Feel + Adjective","ex":[{"en":"What's the matter? — I have a stomachache.","pt":"Qual é o problema? — Estou com dor de estômago."},{"en":"What's wrong? — I have a headache.","pt":"O que houve? — Estou com dor de cabeça."},{"en":"I have the flu. I feel terrible.","pt":"Estou com gripe. Me sinto péssimo."},{"en":"How are you? — I feel sick. I don't feel well.","pt":"Como você está? — Me sinto mal. Não estou bem."},{"en":"He has a backache. He feels awful.","pt":"Ele está com dor nas costas. Está se sentindo horrível."}]},{"page":82,"unit":12,"topic":"Imperatives","ex":[{"en":"Call a dentist.","pt":"Chame um dentista."},{"en":"Don't worry too much.","pt":"Não se preocupe demais."},{"en":"Take a hot bath.","pt":"Tome um banho quente."},{"en":"Don't go to school.","pt":"Não vá para a escola."},{"en":"Don't drink coffee. Stay in bed.","pt":"Não tome café. Fique na cama."}]},{"page":88,"unit":13,"topic":"Prepositions of Place","ex":[{"en":"The department store is on Third Avenue.","pt":"A loja de departamentos fica na Terceira Avenida."},{"en":"It's on the corner of Third and Market.","pt":"Fica na esquina da Third com a Market."},{"en":"It's across from the park.","pt":"Fica em frente ao parque."},{"en":"It's next to the bank.","pt":"Fica ao lado do banco."},{"en":"The bank is between the restaurant and the department store.","pt":"O banco fica entre o restaurante e a loja de departamentos."}]},{"page":90,"unit":13,"topic":"Directions — Giving and Asking","ex":[{"en":"How do I get to Rockefeller Center? — Walk up Fifth Avenue. Turn left on 49th Street. It's on the right.","pt":"Como chego ao Rockefeller Center? — Suba a Fifth Avenue. Vire à esquerda na 49th Street. Fica à direita."},{"en":"How can I get to the New York Public Library? — Walk down Fifth Avenue. Turn right on 42nd Street. It's on the left.","pt":"Como chego à Biblioteca? — Desça a Fifth Avenue. Vire à direita na 42nd Street. Fica à esquerda."},{"en":"Excuse me. How do I get to the Empire State Building? — Walk up 42nd Street. Turn left on...","pt":"Com licença. Como chego ao Empire State? — Suba a 42nd Street. Vire à esquerda na..."},{"en":"How do I get to the bus stop? — Walk down this street and turn right.","pt":"Como chego ao ponto de ônibus? — Desça esta rua e vire à direita."},{"en":"Go straight ahead and turn left at the corner.","pt":"Siga em frente e vire à esquerda na esquina."}]},{"page":93,"unit":14,"topic":"Simple Past Statements — Regular Verbs","ex":[{"en":"On Friday night, I wanted to go out, but my friends didn't call.","pt":"Na sexta à noite, eu quis sair, mas meus amigos não ligaram."},{"en":"I decided to stay home, and I played video games.","pt":"Decidi ficar em casa e joguei videogame."},{"en":"On Saturday, I visited my friend Pablo. We talked and listened to music.","pt":"No sábado, visitei meu amigo Pablo. Conversamos e ouvimos música."},{"en":"In the evening, he invited some friends over, and we cooked a great meal.","pt":"À noite, ele convidou amigos, e fizemos uma ótima refeição."},{"en":"I didn't study at all on Sunday. I just walked to the mall.","pt":"Não estudei nada no domingo. Só caminhei até o shopping."}]},{"page":94,"unit":14,"topic":"Simple Past Statements — Irregular Verbs","ex":[{"en":"I did my homework. I didn't do the laundry.","pt":"Fiz minha lição. Não lavei a roupa."},{"en":"You got up at noon. You didn't get up at 8:00.","pt":"Você acordou ao meio-dia. Não acordou às 8h."},{"en":"She went to the bookstore. She didn't go to the library.","pt":"Ela foi à livraria. Não foi à biblioteca."},{"en":"We met our classmates. We didn't meet our teacher.","pt":"Encontramos nossos colegas. Não encontramos o professor."},{"en":"They had a barbecue. They didn't have a picnic.","pt":"Eles fizeram um churrasco. Não fizeram um piquenique."}]},{"page":95,"unit":14,"topic":"Simple Past Yes/No Questions","ex":[{"en":"Did you have a good summer? — Yes, I did. I had a great summer.","pt":"Você teve um bom verão? — Sim. Tive um ótimo verão."},{"en":"Did you go surfing? — No, I didn't. I went swimming.","pt":"Você fez surf? — Não. Eu nadei."},{"en":"Did Martin like his vacation? — Yes, he did. He liked it a lot.","pt":"O Martin gostou das férias? — Sim, gostou muito."},{"en":"Did Martin and his sister go to Montreal? — No, they didn't. They went to Sydney.","pt":"O Martin e a irmã foram para Montreal? — Não. Foram para Sydney."},{"en":"Did you take any classes last summer? — Yes, I did. I took tennis lessons.","pt":"Você fez aula no verão passado? — Sim. Fiz aula de tênis."}]},{"page":101,"unit":15,"topic":"Past of Be — Was and Were","ex":[{"en":"I was born here.","pt":"Nasci aqui."},{"en":"My family and I were all born in Brazil.","pt":"Minha família e eu nascemos todos no Brasil."},{"en":"My father was a teacher and my mother was an engineer.","pt":"Meu pai era professor e minha mãe era engenheira."},{"en":"Were you in class yesterday? — Yes, I was. / No, I wasn't.","pt":"Você estava na aula ontem? — Sim, estava. / Não, não estava."},{"en":"Were your parents born in the U.S.? — Yes, they were. / No, they weren't.","pt":"Seus pais nasceram nos EUA? — Sim, nasceram. / Não, não nasceram."}]},{"page":103,"unit":15,"topic":"Wh-Questions with Did, Was, and Were","ex":[{"en":"Where did you grow up? — I grew up in New York.","pt":"Onde você cresceu? — Cresci em Nova York."},{"en":"What did your father do there? — He worked in a department store.","pt":"O que seu pai fazia lá? — Trabalhava numa loja de departamentos."},{"en":"When did you come to Los Angeles? — I came in 2008.","pt":"Quando você veio para Los Angeles? — Vim em 2008."},{"en":"Where were you born? — I was born in Brooklyn.","pt":"Onde você nasceu? — Nasci no Brooklyn."},{"en":"What was he like? — He was really friendly.","pt":"Como ele era? — Era muito simpático."}]},{"page":107,"unit":16,"topic":"Subject and Object Pronouns","ex":[{"en":"Can I speak with Ms. Murphy, please? — She's not here, but maybe I can help you.","pt":"Posso falar com a Sra. Murphy? — Ela não está, mas talvez eu possa ajudar."},{"en":"Hi, this is Colin Shaw. Is Mr. Kerr there? — He's not here right now. Do you want to leave him a message?","pt":"Aqui é o Colin Shaw. O Sr. Kerr está? — Ele não está agora. Quer deixar uma mensagem para ele?"},{"en":"Please tell him to call me at work.","pt":"Por favor, peça para ele me ligar no trabalho."},{"en":"Are Lauren and Matt in? — No, they're not. I'm their son.","pt":"A Lauren e o Matt estão? — Não, não estão. Sou filho deles."},{"en":"I found their keys. They left them on the table.","pt":"Encontrei as chaves deles. Eles deixaram as chaves na mesa."}]},{"page":109,"unit":16,"topic":"Invitations — Verb + to","ex":[{"en":"Would you like to go to an art festival this weekend? — I'd like to, but I can't.","pt":"Você gostaria de ir a um festival neste fim de semana? — Eu gostaria, mas não posso."},{"en":"Would you like to go to an amusement park? — Yes, I'd love to.","pt":"Você gostaria de ir a um parque de diversões? — Sim, adoraria."},{"en":"Do you want to see a play with me tonight? — Sure. I'd really like to see a good play.","pt":"Quer ver uma peça comigo hoje à noite? — Claro. Adoraria ver uma boa peça."},{"en":"I'd like to, but I have to work late.","pt":"Eu gostaria, mas preciso trabalhar até tarde."},{"en":"I'd love to, but I need to help my parents.","pt":"Eu adoraria, mas preciso ajudar meus pais."}]}],"lvl1":[{"page":3,"unit":1,"topic":"Statements with Be; Possessive Adjectives","ex":[{"en":"I'm from Brazil.","pt":"Eu sou do Brasil."},{"en":"He's a college student.","pt":"Ele é universitário."},{"en":"We're in the same class.","pt":"Estamos na mesma turma."},{"en":"Her name is Caroline.","pt":"O nome dela é Caroline."},{"en":"Their parents are on vacation.","pt":"Os pais deles estão de férias."}]},{"page":4,"unit":1,"topic":"Wh-Questions with Be","ex":[{"en":"Where's your friend?","pt":"Onde está o seu amigo?"},{"en":"Who's that?","pt":"Quem é aquele/aquela?"},{"en":"What's São Paulo like?","pt":"Como é São Paulo?"},{"en":"Where are you and Vanessa from?","pt":"De onde vocês, você e a Vanessa, são?"},{"en":"How are your classes?","pt":"Como estão as suas aulas?"}]},{"page":5,"unit":1,"topic":"Yes/No Questions and Short Answers with Be","ex":[{"en":"Are you free? — Yes, I am.","pt":"Você está livre? — Estou."},{"en":"Is your class at 2:00? — No, it isn't.","pt":"Sua aula é às 14h? — Não é."},{"en":"Are you and Giovanna from Italy? — Yes, we are.","pt":"Vocês são da Itália? — Somos."},{"en":"Is Mr. Jones from the United States? — No, he's not.","pt":"O Sr. Jones é dos EUA? — Não é."},{"en":"Are your classes interesting? — Yes, they are.","pt":"Suas aulas são interessantes? — São."}]},{"page":10,"unit":2,"topic":"Simple Present Wh-Questions and Statements","ex":[{"en":"What do you do?","pt":"Qual é a sua profissão?"},{"en":"Where does she work?","pt":"Onde ela trabalha?"},{"en":"He teaches an art class.","pt":"Ele dá uma aula de arte."},{"en":"I study the piano.","pt":"Eu estudo piano."},{"en":"How does she like it?","pt":"O que ela acha disso?"}]},{"page":12,"unit":2,"topic":"Time Expressions","ex":[{"en":"I get up at 7:00 in the morning.","pt":"Eu acordo às 7h da manhã."},{"en":"I work late on Wednesdays.","pt":"Eu trabalho até tarde às quartas."},{"en":"On weekends, I go to bed at 1:00 a.m.","pt":"Nos fins de semana, vou dormir à 1h."},{"en":"I read a book before I go to sleep.","pt":"Eu leio um livro antes de dormir."},{"en":"I have lunch at 11:30 on Mondays.","pt":"Eu almoço às 11h30 às segundas."}]},{"page":17,"unit":3,"topic":"Demonstratives; One, Ones","ex":[{"en":"How much is this T-shirt?","pt":"Quanto custa esta camiseta?"},{"en":"Those sneakers are nice.","pt":"Aqueles tênis são legais."},{"en":"Which one? The blue one.","pt":"Qual? O azul."},{"en":"I like the gray ones.","pt":"Eu gosto dos cinza."},{"en":"How much are these?","pt":"Quanto custam estes?"}]},{"page":20,"unit":3,"topic":"Preferences; Comparisons with Adjectives","ex":[{"en":"I prefer the leather one.","pt":"Eu prefiro o de couro."},{"en":"The design is nicer.","pt":"O design é mais bonito."},{"en":"It's more attractive than the brown one.","pt":"É mais atraente que o marrom."},{"en":"The silver ones are cheaper.","pt":"Os prateados são mais baratos."},{"en":"Which one do you like more?","pt":"De qual você gosta mais?"}]},{"page":23,"unit":4,"topic":"Simple Present Questions; Short Answers","ex":[{"en":"Do you like science fiction movies? — Yes, I do.","pt":"Você gosta de ficção científica? — Gosto."},{"en":"Does she play the piano? — No, she doesn't.","pt":"Ela toca piano? — Não toca."},{"en":"What kind of music does Maya like?","pt":"Que tipo de música a Maya curte?"},{"en":"I like them a lot.","pt":"Eu gosto muito deles."},{"en":"Let's download it.","pt":"Vamos baixar isso."}]},{"page":26,"unit":4,"topic":"Would; Verb + to + Verb","ex":[{"en":"Would you like to go to a concert?","pt":"Você gostaria de ir a um show?"},{"en":"Yes, I'd love to. Thanks.","pt":"Sim, eu adoraria. Obrigado."},{"en":"I'd like to, but I have to study.","pt":"Eu gostaria, mas tenho que estudar."},{"en":"I need to save money.","pt":"Eu preciso economizar."},{"en":"I want to visit my parents.","pt":"Eu quero visitar meus pais."}]},{"page":32,"unit":5,"topic":"Present Continuous","ex":[{"en":"What are you doing?","pt":"O que você está fazendo?"},{"en":"I'm eating a sandwich.","pt":"Estou comendo um sanduíche."},{"en":"Is your sister working in another city?","pt":"Sua irmã está trabalhando em outra cidade?"},{"en":"They're studying for their exams.","pt":"Eles estão estudando para as provas."},{"en":"We're having a lot of fun!","pt":"Estamos nos divertindo muito!"}]},{"page":34,"unit":5,"topic":"Quantifiers","ex":[{"en":"Most high school students go to college.","pt":"A maioria dos estudantes do ensino médio vai para a faculdade."},{"en":"A lot of people live alone.","pt":"Muitas pessoas moram sozinhas."},{"en":"Few people are 65 or older.","pt":"Poucas pessoas têm 65 anos ou mais."},{"en":"No one gets married before the age of 18.","pt":"Ninguém se casa antes dos 18."},{"en":"Many families are large.","pt":"Muitas famílias são grandes."}]},{"page":37,"unit":6,"topic":"Adverbs of Frequency","ex":[{"en":"I always exercise before class.","pt":"Eu sempre me exercito antes da aula."},{"en":"She hardly ever watches TV.","pt":"Ela quase nunca assiste TV."},{"en":"I go jogging once a week.","pt":"Eu corro uma vez por semana."},{"en":"He never watches TV.","pt":"Ele nunca assiste TV."},{"en":"Sometimes I watch TV before bed.","pt":"Às vezes assisto TV antes de dormir."}]},{"page":40,"unit":6,"topic":"Questions with How; Short Answers","ex":[{"en":"How often do you go to the beach?","pt":"Com que frequência você vai à praia?"},{"en":"How long do you spend online?","pt":"Quanto tempo você passa online?"},{"en":"How good are you at sports? — Pretty good.","pt":"Você é bom em esportes? — Bem bom."},{"en":"How well do you swim? — Not very well.","pt":"Quão bem você nada? — Não muito bem."},{"en":"How often do you lift weights? — About three times a week.","pt":"Com que frequência você malha? — Umas três vezes por semana."}]},{"page":45,"unit":7,"topic":"Simple Past","ex":[{"en":"She danced with some friends.","pt":"Ela dançou com alguns amigos."},{"en":"Did you go anywhere last weekend? — Yes, I did.","pt":"Você foi a algum lugar no fim de semana? — Fui."},{"en":"I bought a new phone.","pt":"Eu comprei um celular novo."},{"en":"He stayed home and studied.","pt":"Ele ficou em casa e estudou."},{"en":"I didn't spend any money.","pt":"Eu não gastei dinheiro nenhum."}]},{"page":47,"unit":7,"topic":"Past of Be","ex":[{"en":"Was the weather OK? — No, it wasn't.","pt":"O tempo estava bom? — Não estava."},{"en":"Were your parents there? — No, they weren't.","pt":"Seus pais estavam lá? — Não estavam."},{"en":"It was excellent!","pt":"Foi excelente!"},{"en":"How long were you away?","pt":"Por quanto tempo você ficou fora?"},{"en":"I was there on business.","pt":"Eu estava lá a trabalho."}]},{"page":51,"unit":8,"topic":"There Is, There Are; One, Any, Some","ex":[{"en":"Is there a gym around here? — Yes, there is.","pt":"Tem uma academia por aqui? — Tem."},{"en":"Are there any restaurants on Main Street?","pt":"Tem algum restaurante na Main Street?"},{"en":"There's one next to the library.","pt":"Tem um do lado da biblioteca."},{"en":"There are some nice stores on Third Avenue.","pt":"Tem umas lojas legais na Third Avenue."},{"en":"No, there aren't any around here.","pt":"Não, não tem nenhum por aqui."}]},{"page":54,"unit":8,"topic":"Quantifiers; How Many and How Much","ex":[{"en":"How many drugstores are there? — There are a few.","pt":"Quantas farmácias tem? — Algumas."},{"en":"Is there much pollution? — No, there isn't much.","pt":"Tem muita poluição? — Não muita."},{"en":"Are there many parks? — No, there aren't any.","pt":"Tem muitos parques? — Não, nenhum."},{"en":"How much traffic is there?","pt":"Quanto trânsito tem?"},{"en":"There's a little crime.","pt":"Tem um pouco de crime."}]},{"page":59,"unit":9,"topic":"Describing People","ex":[{"en":"What does he look like?","pt":"Como ele é fisicamente?"},{"en":"How long is her hair? — It's pretty short.","pt":"Quão comprido é o cabelo dela? — Bem curto."},{"en":"What color is his hair? — It's dark brown.","pt":"De que cor é o cabelo dele? — Castanho-escuro."},{"en":"He's in his twenties.","pt":"Ele tem uns vinte e poucos anos."},{"en":"She's about 32.","pt":"Ela tem uns 32."}]},{"page":62,"unit":9,"topic":"Modifiers with Present Participles and Prepositions","ex":[{"en":"He's the one talking to Brooke.","pt":"Ele é o que está falando com a Brooke."},{"en":"Kyle is the tall guy wearing a yellow shirt.","pt":"O Kyle é o cara alto de camisa amarela."},{"en":"She's the tall one in jeans.","pt":"Ela é a alta de jeans."},{"en":"They're the people next to the window.","pt":"Eles são as pessoas perto da janela."},{"en":"J.P. is the boy playing a video game.","pt":"O J.P. é o menino jogando videogame."}]},{"page":65,"unit":10,"topic":"Present Perfect; Already, Yet","ex":[{"en":"Have you been to a jazz club? — Yes, I've been to several.","pt":"Você já foi a um clube de jazz? — Já fui a vários."},{"en":"Has Carlos visited the theme parks? — No, he hasn't.","pt":"O Carlos visitou os parques? — Não visitou."},{"en":"I've already made dinner twice this week.","pt":"Eu já fiz o jantar duas vezes esta semana."},{"en":"I haven't gone to any parties yet.","pt":"Eu ainda não fui a nenhuma festa."},{"en":"Have you played any sports this month?","pt":"Você praticou algum esporte este mês?"}]},{"page":66,"unit":10,"topic":"Present Perfect vs. Simple Past","ex":[{"en":"Have you ever seen an alligator? — Yes, I have.","pt":"Você já viu um jacaré? — Já vi."},{"en":"I saw a big alligator last week.","pt":"Eu vi um jacaré grande semana passada."},{"en":"I've never tried it.","pt":"Eu nunca experimentei isso."},{"en":"I didn't go to the park last week.","pt":"Eu não fui ao parque semana passada."},{"en":"No, I never tried it when I lived there.","pt":"Não, nunca experimentei quando morava lá."}]},{"page":67,"unit":10,"topic":"For and Since","ex":[{"en":"I've been a college student for almost four years.","pt":"Sou universitário há quase quatro anos."},{"en":"My parents have been on vacation since Monday.","pt":"Meus pais estão de férias desde segunda."},{"en":"Alex and Brianna have been best friends since high school.","pt":"Alex e Brianna são melhores amigos desde o ensino médio."},{"en":"I haven't gone to a party for a long time.","pt":"Faz muito tempo que não vou a uma festa."},{"en":"Hiroshi has been at work since 6:00 a.m.","pt":"O Hiroshi está no trabalho desde as 6h."}]},{"page":73,"unit":11,"topic":"Adverbs Before Adjectives; Conjunctions","ex":[{"en":"Punta Cana is really nice.","pt":"Punta Cana é bem legal."},{"en":"New York is too noisy for me.","pt":"Nova York é barulhenta demais pra mim."},{"en":"Kyoto is very nice, and everyone is extremely friendly.","pt":"Kyoto é muito legal, e todos são extremamente simpáticos."},{"en":"The weather is nice. Summers get pretty hot, however.","pt":"O tempo é bom. Os verões ficam bem quentes, no entanto."},{"en":"It's an amazing city, and I love to go there.","pt":"É uma cidade incrível, e adoro ir lá."}]},{"page":75,"unit":11,"topic":"Modal Verbs Can and Should","ex":[{"en":"You can't miss the street food.","pt":"Você não pode perder a comida de rua."},{"en":"You should go to Morocco.","pt":"Você deveria ir ao Marrocos."},{"en":"You shouldn't miss the Grand Bazaar.","pt":"Você não deve perder o Grand Bazaar."},{"en":"Can I rent a car?","pt":"Posso/dá pra alugar um carro?"},{"en":"You should definitely use the subway.","pt":"Você deveria com certeza usar o metrô."}]},{"page":79,"unit":12,"topic":"Adjective + Infinitive; Noun + Infinitive","ex":[{"en":"It's important to get some rest.","pt":"É importante descansar."},{"en":"It's sometimes helpful to drink garlic tea.","pt":"Às vezes ajuda tomar chá de alho."},{"en":"It's a good idea to put a heating pad on it.","pt":"É uma boa ideia colocar uma bolsa térmica."},{"en":"It's important to see a doctor.","pt":"É importante ir ao médico."},{"en":"For an earache, it's a good idea to see a doctor.","pt":"Para dor de ouvido, é uma boa ideia ir ao médico."}]},{"page":81,"unit":12,"topic":"Modal Verbs Can, Could, and May for Requests; Suggestions","ex":[{"en":"May I help you?","pt":"Posso ajudar?"},{"en":"Can I have a bag of cough drops?","pt":"Posso levar um pacote de pastilhas?"},{"en":"What do you suggest for a backache?","pt":"O que você sugere para dor nas costas?"},{"en":"You could try this new cream.","pt":"Você poderia experimentar esse creme novo."},{"en":"Why don't you try this lotion?","pt":"Por que você não experimenta esta loção?"}]},{"page":87,"unit":13,"topic":"So, Too, Neither, Either","ex":[{"en":"I like Japanese food. — So do I.","pt":"Gosto de comida japonesa. — Eu também."},{"en":"I can eat spicy food. — So can I.","pt":"Consigo comer comida apimentada. — Eu também."},{"en":"I'm not in the mood for Indian food. — Neither am I.","pt":"Não estou a fim de comida indiana. — Nem eu."},{"en":"I don't like salty food. — I don't either.","pt":"Não gosto de comida salgada. — Eu também não."},{"en":"I'm crazy about Italian food. — So am I.","pt":"Sou louco por comida italiana. — Eu também."}]},{"page":89,"unit":13,"topic":"Modal Verbs Would and Will for Requests","ex":[{"en":"What would you like to drink?","pt":"O que você gostaria de beber?"},{"en":"I'd like onion soup, please.","pt":"Eu gostaria de sopa de cebola, por favor."},{"en":"I'll have the soup of the day.","pt":"Vou querer a sopa do dia."},{"en":"Would you like anything else? — That's all, thanks.","pt":"Mais alguma coisa? — Só isso, obrigado."},{"en":"I'll have mint chocolate chip, please.","pt":"Vou querer menta com gotas de chocolate."}]},{"page":93,"unit":14,"topic":"Comparisons with Adjectives","ex":[{"en":"Which country is larger, Australia or Mexico?","pt":"Qual país é maior, Austrália ou México?"},{"en":"Malta is more crowded than England.","pt":"Malta é mais populosa que a Inglaterra."},{"en":"Which city is the most expensive?","pt":"Qual cidade é a mais cara?"},{"en":"The Nile is the longest river in the world.","pt":"O Nilo é o rio mais longo do mundo."},{"en":"Russia is the largest country.","pt":"A Rússia é o maior país."}]},{"page":96,"unit":14,"topic":"Questions with How","ex":[{"en":"How high is Niagara Falls? — It's 52 meters high.","pt":"Qual a altura das Cataratas do Niágara? — 52 metros."},{"en":"How long is the Nile? — It's 6,670 kilometers long.","pt":"Qual o comprimento do Nilo? — 6.670 km."},{"en":"How far is Osaka from Tokyo? — About 400 kilometers.","pt":"Qual a distância de Osaka a Tóquio? — Uns 400 km."},{"en":"How deep is the Grand Canyon?","pt":"Qual a profundidade do Grand Canyon?"},{"en":"How hot is it in the summer?","pt":"Quão quente fica no verão?"}]},{"page":101,"unit":15,"topic":"Future with Present Continuous and Be Going to","ex":[{"en":"What are you doing tonight? — I'm going to a party.","pt":"O que você vai fazer hoje à noite? — Vou a uma festa."},{"en":"She's going to see a play.","pt":"Ela vai ver uma peça."},{"en":"Are they going to see the photo exhibit? — Yes, they are.","pt":"Eles vão ver a exposição? — Vão."},{"en":"Are you doing anything tomorrow?","pt":"Você vai fazer algo amanhã?"},{"en":"We're going to have a barbecue on Sunday.","pt":"Vamos fazer um churrasco no domingo."}]},{"page":103,"unit":15,"topic":"Formal and Informal Messages with Tell and Ask","ex":[{"en":"Please tell Haru that the barbecue is on Saturday.","pt":"Por favor, diga ao Haru que o churrasco é no sábado."},{"en":"Could you tell Mia that the dance performance is tonight?","pt":"Você poderia avisar a Mia que a apresentação é hoje?"},{"en":"Would you ask Maika to meet me at the stadium?","pt":"Você poderia pedir à Maika para me encontrar no estádio?"},{"en":"Could you ask Caitlin to call me at 4:00?","pt":"Você poderia pedir à Caitlin que me ligue às 16h?"},{"en":"Please ask Garrett to bring the tickets.","pt":"Por favor, peça ao Garrett que traga os ingressos."}]},{"page":107,"unit":16,"topic":"Describing Changes","ex":[{"en":"I've just started a new job.","pt":"Acabei de começar um emprego novo."},{"en":"I'm not in high school anymore.","pt":"Não estou mais no ensino médio."},{"en":"I got married.","pt":"Eu me casei."},{"en":"My life is easier now.","pt":"Minha vida está mais fácil agora."},{"en":"It's less noisy than downtown.","pt":"É menos barulhento que o centro."}]},{"page":109,"unit":16,"topic":"Verb + Infinitive","ex":[{"en":"I'm going to take a trip to the Caribbean.","pt":"Vou fazer uma viagem ao Caribe."},{"en":"I hope to get a new job.","pt":"Espero conseguir um emprego novo."},{"en":"I'd like to travel around the United States.","pt":"Eu gostaria de viajar pelos EUA."},{"en":"I don't plan to take guitar lessons.","pt":"Não pretendo fazer aulas de violão."},{"en":"I'd love to play the guitar.","pt":"Eu adoraria tocar violão."}]}],"lvl2":[{"page":3,"unit":1,"topic":"Past Tense","ex":[{"en":"Where were you born? — I was born in Córdoba.","pt":"Onde você nasceu? — Nasci em Córdoba."},{"en":"When did you move here? — I moved here 10 years ago.","pt":"Quando você se mudou pra cá? — Há 10 anos."},{"en":"Did you take English classes? — Yes, I did.","pt":"Você fez aulas de inglês? — Fiz."},{"en":"My aunt taught me at home.","pt":"Minha tia me ensinou em casa."},{"en":"Did you grow up there? — No, I grew up in Canada.","pt":"Você cresceu lá? — Não, cresci no Canadá."}]},{"page":5,"unit":1,"topic":"Used to","ex":[{"en":"Did you use to have pets? — Yes, I used to have a cat.","pt":"Você costumava ter animais? — Sim, eu tinha um gato."},{"en":"I never used to play sports, but now I like to keep fit.","pt":"Eu nunca praticava esportes, mas agora gosto de me manter em forma."},{"en":"I used to wear my hair much longer.","pt":"Eu costumava usar o cabelo bem mais comprido."},{"en":"I didn't use to like studying, but now I love it.","pt":"Eu não gostava de estudar, mas agora adoro."},{"en":"We didn't use to play during the week.","pt":"A gente não brincava durante a semana."}]},{"page":9,"unit":2,"topic":"Expressions of Quantity","ex":[{"en":"There are too many cars.","pt":"Há carros demais."},{"en":"There should be less pollution.","pt":"Deveria haver menos poluição."},{"en":"We need more public transportation.","pt":"Precisamos de mais transporte público."},{"en":"There aren't enough police officers.","pt":"Não há policiais suficientes."},{"en":"There isn't enough parking.","pt":"Não há vagas de estacionamento suficientes."}]},{"page":11,"unit":2,"topic":"Indirect Questions from Wh-Questions","ex":[{"en":"Could you tell me where the restrooms are?","pt":"Você poderia me dizer onde ficam os banheiros?"},{"en":"Do you know what time the post office opens?","pt":"Você sabe que horas abre o correio?"},{"en":"Do you know where I can rent a car?","pt":"Você sabe onde posso alugar um carro?"},{"en":"Can you tell me how much a city tour costs?","pt":"Você pode me dizer quanto custa um city tour?"},{"en":"Do you know where the nearest Wi-Fi hotspot is?","pt":"Você sabe onde fica o Wi-Fi mais próximo?"}]},{"page":17,"unit":3,"topic":"Evaluations and Comparisons","ex":[{"en":"Our apartment isn't big enough for our family.","pt":"Nosso apartamento não é grande o suficiente para a família."},{"en":"This apartment is too hot.","pt":"Este apartamento é quente demais."},{"en":"The location is just as convenient as the old one.","pt":"A localização é tão conveniente quanto a antiga."},{"en":"We don't have as many bedrooms as we used to.","pt":"Não temos tantos quartos quanto tínhamos."},{"en":"The neighbors make too much noise.","pt":"Os vizinhos fazem barulho demais."}]},{"page":20,"unit":3,"topic":"Wish","ex":[{"en":"I wish I didn't live with my parents.","pt":"Eu queria não morar com meus pais."},{"en":"I wish I had my own apartment.","pt":"Eu queria ter meu próprio apartamento."},{"en":"I wish it weren't so difficult.","pt":"Eu queria que não fosse tão difícil."},{"en":"I wish I could move out.","pt":"Eu queria poder me mudar."},{"en":"I wish they would stop worrying about me.","pt":"Eu queria que parassem de se preocupar comigo."}]},{"page":23,"unit":4,"topic":"Simple Past vs. Present Perfect","ex":[{"en":"Have you ever eaten frog legs? — Yes, I have.","pt":"Você já comeu coxa de rã? — Já."},{"en":"I tried them last month.","pt":"Eu experimentei mês passado."},{"en":"Have you ever been to a Vietnamese restaurant? — No, I haven't.","pt":"Você já foi a um restaurante vietnamita? — Não."},{"en":"Did you go alone? — No, I went with some friends.","pt":"Você foi sozinho? — Não, fui com amigos."},{"en":"I ate a huge breakfast.","pt":"Eu tomei um café da manhã enorme."}]},{"page":25,"unit":4,"topic":"Sequence Adverbs","ex":[{"en":"First, boil the macaroni in a large pot.","pt":"Primeiro, ferva o macarrão numa panela grande."},{"en":"Then melt the butter on medium heat.","pt":"Depois, derreta a manteiga em fogo médio."},{"en":"Next, add the cheese.","pt":"Em seguida, adicione o queijo."},{"en":"After that, add the cooked macaroni.","pt":"Depois disso, adicione o macarrão cozido."},{"en":"Finally, bake for 20 minutes.","pt":"Por fim, asse por 20 minutos."}]},{"page":31,"unit":5,"topic":"Future with Be Going to and Will","ex":[{"en":"What are you going to do? — I'm going to relax at the beach.","pt":"O que você vai fazer? — Vou relaxar na praia."},{"en":"We're going to go surfing every day.","pt":"Vamos surfar todo dia."},{"en":"I'm not sure. I guess I'll just stay home.","pt":"Não sei. Acho que vou só ficar em casa."},{"en":"Maybe I'll take a course.","pt":"Talvez eu faça um curso."},{"en":"I probably won't go anywhere.","pt":"Provavelmente não vou a lugar nenhum."}]},{"page":33,"unit":5,"topic":"Modals for Necessity and Suggestion","ex":[{"en":"You must have health insurance.","pt":"Você precisa ter plano de saúde."},{"en":"You don't have to get vaccinations.","pt":"Você não precisa tomar vacinas."},{"en":"You'd better avoid the stalls on the street.","pt":"É melhor você evitar as barracas de rua."},{"en":"You ought to make a copy of your passport.","pt":"Você deveria fazer uma cópia do passaporte."},{"en":"You shouldn't carry a lot of cash.","pt":"Você não deveria andar com muito dinheiro."}]},{"page":37,"unit":6,"topic":"Two-Part Verbs; Will for Responding to Requests","ex":[{"en":"Turn down the TV. / Turn the TV down.","pt":"Abaixe a TV."},{"en":"Turn it down.","pt":"Abaixe ela."},{"en":"Put away your books. — All right. I'll put them away.","pt":"Guarde seus livros. — Tá bom, vou guardá-los."},{"en":"Please turn off the lights.","pt":"Por favor, apague as luzes."},{"en":"Pick up your things, please.","pt":"Pegue suas coisas, por favor."}]},{"page":39,"unit":6,"topic":"Requests with Modals and Would You Mind ... ?","ex":[{"en":"Can you keep your cat inside, please?","pt":"Você pode manter o gato dentro de casa, por favor?"},{"en":"Would you please park your car in your space?","pt":"Você poderia estacionar na sua vaga, por favor?"},{"en":"Would you mind keeping your cat inside?","pt":"Você se importaria de manter o gato dentro de casa?"},{"en":"Would you mind speaking more quietly?","pt":"Você se importaria de falar mais baixo?"},{"en":"Would you mind not using your phone in class?","pt":"Você se importaria de não usar o celular na aula?"}]},{"page":45,"unit":7,"topic":"Infinitives and Gerunds for Uses and Purposes","ex":[{"en":"I use my cell phone to send messages.","pt":"Uso meu celular para enviar mensagens."},{"en":"I use my cell phone for sending messages.","pt":"Uso meu celular para enviar mensagens."},{"en":"People often use their phones to take photos.","pt":"As pessoas costumam usar o celular para tirar fotos."},{"en":"Many people use tablets for making video calls.","pt":"Muita gente usa tablets para fazer videochamadas."},{"en":"Engineers use 3-D printers to make car parts.","pt":"Engenheiros usam impressoras 3D para fazer peças de carro."}]},{"page":47,"unit":7,"topic":"Imperatives and Infinitives for Giving Suggestions","ex":[{"en":"Be sure to update the app.","pt":"Não deixe de atualizar o aplicativo."},{"en":"Make sure to charge your phone.","pt":"Certifique-se de carregar o celular."},{"en":"Remember to back up your files.","pt":"Lembre-se de fazer backup dos arquivos."},{"en":"Don't forget to reset your passwords.","pt":"Não esqueça de redefinir suas senhas."},{"en":"Try not to use public Wi-Fi networks.","pt":"Tente não usar redes Wi-Fi públicas."}]},{"page":51,"unit":8,"topic":"Relative Clauses of Time","ex":[{"en":"Mother's Day is a day when my kids make pancakes for me.","pt":"O Dia das Mães é um dia em que meus filhos fazem panquecas pra mim."},{"en":"New Year's Eve is a night when I have fun with my friends.","pt":"O Réveillon é uma noite em que me divirto com os amigos."},{"en":"April Fools' Day is a day when people play tricks on friends.","pt":"O Dia da Mentira é um dia em que as pessoas pregam peças."},{"en":"Summer is a time when many people go to the beach.","pt":"O verão é uma época em que muita gente vai à praia."},{"en":"Valentine's Day is a day when people express their love.","pt":"O Dia dos Namorados é um dia em que as pessoas declaram seu amor."}]},{"page":54,"unit":8,"topic":"Adverbial Clauses of Time","ex":[{"en":"When women get married, they usually wear a brightly colored sari.","pt":"Quando as mulheres se casam, costumam usar um sári colorido."},{"en":"After the groom arrives, the bride and groom exchange garlands.","pt":"Depois que o noivo chega, os noivos trocam guirlandas."},{"en":"Before the wedding, the relatives have a party.","pt":"Antes do casamento, os parentes fazem uma festa."},{"en":"When a couple gets engaged, the man often gives a ring.","pt":"Quando um casal fica noivo, o homem costuma dar um anel."},{"en":"Before a man and woman get married, they usually date.","pt":"Antes de se casarem, o homem e a mulher costumam namorar."}]},{"page":59,"unit":9,"topic":"Time Contrasts","ex":[{"en":"A few years ago, there were just houses here.","pt":"Alguns anos atrás, só havia casas aqui."},{"en":"These days, they're building lots of apartments.","pt":"Hoje em dia, estão construindo muitos apartamentos."},{"en":"In the past, kids used to hang out with friends after school.","pt":"No passado, as crianças saíam com amigos depois da escola."},{"en":"In the future, restaurants might not exist.","pt":"No futuro, talvez restaurantes não existam."},{"en":"In a few years, we are going to have virtual friends.","pt":"Em alguns anos, vamos ter amigos virtuais."}]},{"page":61,"unit":9,"topic":"Conditional Sentences with If Clauses","ex":[{"en":"If you get a high-paying job, you'll have more cash to spend.","pt":"Se você conseguir um emprego bem pago, terá mais dinheiro."},{"en":"If you don't save your money, you won't save anything.","pt":"Se você não economizar, não vai guardar nada."},{"en":"If you travel abroad, you'll be able to experience a new culture.","pt":"Se você viajar para o exterior, vai conhecer uma nova cultura."},{"en":"If you eat less fast food, you might feel a lot healthier.","pt":"Se comer menos fast food, você pode se sentir bem mais saudável."},{"en":"If you don't get enough sleep, you won't be able to stay awake.","pt":"Se não dormir o suficiente, não vai conseguir ficar acordado."}]},{"page":65,"unit":10,"topic":"Gerunds; Short Responses","ex":[{"en":"I love playing video games. — So do I.","pt":"Adoro jogar videogame. — Eu também."},{"en":"I'm good at solving problems. — So am I.","pt":"Sou bom em resolver problemas. — Eu também."},{"en":"I don't mind working evenings. — Neither do I.","pt":"Não me importo de trabalhar à noite. — Nem eu."},{"en":"I can't stand commuting. — Neither can I.","pt":"Não suporto o deslocamento. — Nem eu."},{"en":"I'm interested in learning foreign languages.","pt":"Tenho interesse em aprender línguas estrangeiras."}]},{"page":68,"unit":10,"topic":"Clauses with Because","ex":[{"en":"I'd make a good journalist because I'm good at writing.","pt":"Eu seria um bom jornalista porque sou bom em escrever."},{"en":"I could be a teacher because I'm very creative.","pt":"Eu poderia ser professor porque sou muito criativo."},{"en":"I could never be a stockbroker because I can't make decisions quickly.","pt":"Eu nunca poderia ser corretor porque não tomo decisões rápido."},{"en":"I'd like to be a physical therapist because I enjoy helping people.","pt":"Eu gostaria de ser fisioterapeuta porque gosto de ajudar as pessoas."},{"en":"I would make a bad librarian because I'm very disorganized.","pt":"Eu seria um péssimo bibliotecário porque sou muito desorganizado."}]},{"page":73,"unit":11,"topic":"Passive with by (Simple Past)","ex":[{"en":"It was founded by the Disney brothers in 1923.","pt":"Foi fundada pelos irmãos Disney em 1923."},{"en":"Disneyland was opened by Walt Disney in 1955.","pt":"A Disneyland foi inaugurada por Walt Disney em 1955."},{"en":"The Statue of Liberty was designed by Bartholdi.","pt":"A Estátua da Liberdade foi projetada por Bartholdi."},{"en":"The first iPad was released in 2010.","pt":"O primeiro iPad foi lançado em 2010."},{"en":"The novel was written by Gabriel García Márquez.","pt":"O romance foi escrito por Gabriel García Márquez."}]},{"page":75,"unit":11,"topic":"Passive without by (Simple Present)","ex":[{"en":"The euro is used in most of Europe.","pt":"O euro é usado na maior parte da Europa."},{"en":"Credit cards are accepted at most places.","pt":"Cartões de crédito são aceitos na maioria dos lugares."},{"en":"Rice is grown in many Asian countries.","pt":"Arroz é cultivado em muitos países asiáticos."},{"en":"Cars and electronics are manufactured in Japan.","pt":"Carros e eletrônicos são fabricados no Japão."},{"en":"French and Flemish are spoken in Belgium.","pt":"Francês e flamengo são falados na Bélgica."}]},{"page":79,"unit":12,"topic":"Past Continuous vs. Simple Past","ex":[{"en":"I was having lunch when I spilled coffee on my clothes.","pt":"Eu estava almoçando quando derramei café na roupa."},{"en":"I was driving to the airport, but I got a flat tire.","pt":"Eu estava indo de carro ao aeroporto, mas furou o pneu."},{"en":"While I was shopping one day, a celebrity walked into the store.","pt":"Enquanto eu fazia compras um dia, uma celebridade entrou na loja."},{"en":"My father was skiing when he broke his leg.","pt":"Meu pai estava esquiando quando quebrou a perna."},{"en":"While I was driving in England, I realized I was on the wrong side.","pt":"Enquanto dirigia na Inglaterra, percebi que estava no lado errado."}]},{"page":81,"unit":12,"topic":"Present Perfect Continuous","ex":[{"en":"What have you been doing lately?","pt":"O que você anda fazendo ultimamente?"},{"en":"I've been working two jobs for the last six months.","pt":"Estou trabalhando em dois empregos nos últimos seis meses."},{"en":"How long have you been trying? — Since I graduated.","pt":"Há quanto tempo você está tentando? — Desde que me formei."},{"en":"I haven't been saving money. I've been spending it!","pt":"Não estou economizando. Estou gastando!"},{"en":"I've been running three times a week.","pt":"Tenho corrido três vezes por semana."}]},{"page":87,"unit":13,"topic":"Participles as Adjectives","ex":[{"en":"Stephen King's books are fascinating.","pt":"Os livros do Stephen King são fascinantes."},{"en":"I'm fascinated by Stephen King's books.","pt":"Sou fascinado pelos livros do Stephen King."},{"en":"I think action movies are boring.","pt":"Acho filmes de ação entediantes."},{"en":"I'm bored by action movies.","pt":"Fico entediado com filmes de ação."},{"en":"John Cho is an amazing actor. I'm always amazed by his talent.","pt":"O John Cho é um ator incrível. Sempre fico impressionado com o talento dele."}]},{"page":89,"unit":13,"topic":"Relative Pronouns for People and Things","ex":[{"en":"He's an actor who is also a director and producer.","pt":"Ele é um ator que também é diretor e produtor."},{"en":"It's a science fiction fantasy that has become a franchise.","pt":"É uma fantasia de ficção científica que virou uma franquia."},{"en":"Jennifer Hudson is a singer who has acted in several films.","pt":"Jennifer Hudson é uma cantora que atuou em vários filmes."},{"en":"Wii Fit is a video game that helps people get more exercise.","pt":"Wii Fit é um videogame que ajuda as pessoas a se exercitarem mais."},{"en":"Michael Keaton is an actor who began his career as a cameraman.","pt":"Michael Keaton é um ator que começou como cinegrafista."}]},{"page":93,"unit":14,"topic":"Modals and Adverbs","ex":[{"en":"It might mean she wants to accept it.","pt":"Pode ser que ela queira aceitar."},{"en":"Maybe it means she wants to accept it.","pt":"Talvez signifique que ela quer aceitar."},{"en":"It could mean she doesn't want anything.","pt":"Pode significar que ela não quer nada."},{"en":"That must mean \"no.\"","pt":"Isso só pode significar \"não\"."},{"en":"That definitely means \"no.\"","pt":"Isso com certeza significa \"não\"."}]},{"page":95,"unit":14,"topic":"Permission, Obligation, and Prohibition","ex":[{"en":"You can swim here.","pt":"Você pode nadar aqui."},{"en":"You're allowed to park here.","pt":"É permitido estacionar aqui."},{"en":"You have to fasten your seat belt.","pt":"Você tem que colocar o cinto de segurança."},{"en":"You've got to take off your shoes.","pt":"Você tem que tirar os sapatos."},{"en":"Pets aren't allowed in this area.","pt":"Animais não são permitidos nesta área."}]},{"page":101,"unit":15,"topic":"Unreal Conditional Sentences with If Clauses","ex":[{"en":"If I found $40,000, I would keep it.","pt":"Se eu achasse 40 mil dólares, eu ficaria com eles."},{"en":"I wouldn't return it.","pt":"Eu não devolveria."},{"en":"I could buy a new car.","pt":"Eu poderia comprar um carro novo."},{"en":"If you had three months to travel, where would you go?","pt":"Se você tivesse três meses para viajar, para onde iria?"},{"en":"If your doctor told you to exercise, which activity would you choose?","pt":"Se seu médico mandasse se exercitar, qual atividade você escolheria?"}]},{"page":103,"unit":15,"topic":"Past Modals","ex":[{"en":"You should have told her about it.","pt":"Você deveria ter contado a ela."},{"en":"You shouldn't have lied to your sister.","pt":"Você não deveria ter mentido para sua irmã."},{"en":"What would you have done? — I would have called him.","pt":"O que você teria feito? — Eu teria ligado pra ele."},{"en":"I wouldn't have texted him.","pt":"Eu não teria mandado mensagem pra ele."},{"en":"You should have said something.","pt":"Você deveria ter dito alguma coisa."}]},{"page":107,"unit":16,"topic":"Reported Speech: Requests","ex":[{"en":"She told me to arrive on time for the meeting.","pt":"Ela me disse para chegar na hora da reunião."},{"en":"He told me not to leave my bike in the hallway.","pt":"Ele me disse para não deixar minha bici no corredor."},{"en":"She asked me to pick up some food on the way home.","pt":"Ela me pediu para comprar comida no caminho de casa."},{"en":"He told them to meet at his apartment at 7:30.","pt":"Ele disse a eles para se encontrarem no apartamento dele às 19h30."},{"en":"Aki asked us to help her clean up.","pt":"A Aki nos pediu para ajudá-la a limpar."}]},{"page":109,"unit":16,"topic":"Reported Speech: Statements","ex":[{"en":"She said she wasn't feeling well.","pt":"Ela disse que não estava se sentindo bem."},{"en":"She said she had houseguests for the weekend.","pt":"Ela disse que tinha visitas para o fim de semana."},{"en":"They told me they couldn't come tomorrow.","pt":"Eles me disseram que não podiam vir amanhã."},{"en":"They said they would be out of town.","pt":"Eles disseram que estariam fora da cidade."},{"en":"Mason said he already had plans for Saturday.","pt":"O Mason disse que já tinha planos para sábado."}]}],"lvl3":[{"page":3,"unit":1,"topic":"Relative Pronouns (Who/That)","ex":[{"en":"I like people who aren't too serious.","pt":"Gosto de gente que não é séria demais."},{"en":"I have some good, old friends who/that I met in middle school.","pt":"Tenho bons e velhos amigos que conheci no ensino fundamental."},{"en":"I'd like to have a boss who/that I can respect as a leader.","pt":"Eu gostaria de ter um chefe que eu possa respeitar como líder."},{"en":"I'm looking for a partner who/that I have a lot in common with.","pt":"Estou procurando um parceiro com quem eu tenha muito em comum."}]},{"page":6,"unit":1,"topic":"It Clauses + Adverbial Clauses with When","ex":[{"en":"I don't mind it when a friend answers the phone at the dinner table.","pt":"Não me incomoda quando um amigo atende o telefone na mesa de jantar."},{"en":"I can't stand it when people tell me to calm down.","pt":"Não suporto quando me mandam ficar calmo."},{"en":"It bothers me when my doctor arrives late for an appointment.","pt":"Me incomoda quando meu médico chega atrasado para a consulta."},{"en":"It upsets me when a close friend forgets my birthday.","pt":"Me chateia quando um amigo próximo esquece meu aniversário."}]},{"page":9,"unit":2,"topic":"Gerund Phrases (Subjects and Objects)","ex":[{"en":"Being a flight attendant sounds exciting.","pt":"Ser comissário de bordo parece empolgante."},{"en":"Working as a veterinarian could be rewarding.","pt":"Trabalhar como veterinário pode ser gratificante."},{"en":"He'd love being a flight attendant.","pt":"Ele adoraria ser comissário de bordo."},{"en":"She'd be good at testing games.","pt":"Ela seria boa em testar jogos."}]},{"page":11,"unit":2,"topic":"Comparisons","ex":[{"en":"Sales associates have better hours than firefighters.","pt":"Vendedores têm horários melhores que bombeiros."},{"en":"A career in banking is more demanding than a career in sales.","pt":"Uma carreira em banco é mais exigente que uma em vendas."},{"en":"Game testers don't need as much experience as software developers.","pt":"Testadores de jogos não precisam de tanta experiência quanto desenvolvedores."},{"en":"Nutritionists aren't as well paid as doctors.","pt":"Nutricionistas não são tão bem pagos quanto médicos."}]},{"page":17,"unit":3,"topic":"Requests with Modals, If Clauses, and Gerunds","ex":[{"en":"Is it OK if I use your credit card?","pt":"Tudo bem se eu usar seu cartão de crédito?"},{"en":"Would it be all right if I used your credit card?","pt":"Tudo bem se eu usasse seu cartão de crédito? — mais formal"},{"en":"I was wondering if you could help me move.","pt":"Eu queria saber se você poderia me ajudar na mudança."},{"en":"Would you mind feeding my cats while I'm on vacation?","pt":"Você se importaria de alimentar meus gatos enquanto eu viajo?"}]},{"page":20,"unit":3,"topic":"Indirect Requests","ex":[{"en":"Can you tell Mary not to forget the students' reports?","pt":"Você pode dizer à Mary para não esquecer os relatórios dos alunos?"},{"en":"Could you ask whether or not she is coming to the meeting?","pt":"Você poderia perguntar se ela vem ou não à reunião?"},{"en":"Could you ask Mary if she got my message about her phone?","pt":"Você poderia perguntar à Mary se ela recebeu minha mensagem?"},{"en":"Would you ask her what time I can talk to her about my homework?","pt":"Você perguntaria a ela a que horas posso falar sobre minha lição?"}]},{"page":23,"unit":4,"topic":"Past Continuous vs. Simple Past","ex":[{"en":"As scientists were doing research, they discovered that women need more sleep.","pt":"Enquanto os cientistas pesquisavam, descobriram que mulheres precisam de mais sono."},{"en":"A man was looking for his cat when he found a suspicious package.","pt":"Um homem procurava seu gato quando encontrou um pacote suspeito."},{"en":"As she was walking home, she remembered she had left $20 in her pocket.","pt":"Enquanto caminhava para casa, ela lembrou que tinha deixado 20 dólares no bolso."},{"en":"While Diane was driving to work, she had a bad accident.","pt":"Enquanto Diane dirigia para o trabalho, ela sofreu um grave acidente."}]},{"page":25,"unit":4,"topic":"Past Perfect","ex":[{"en":"I took a trip to London last year. I hadn't traveled abroad before.","pt":"Fiz uma viagem a Londres ano passado. Eu não tinha viajado para o exterior antes."},{"en":"I was visiting the museum when I ran into a friend I hadn't seen for 10 years.","pt":"Eu visitava o museu quando esbarrei num amigo que eu não via há 10 anos."},{"en":"We ran out of gas because we had forgotten to fill up the tank.","pt":"Ficamos sem gasolina porque tínhamos esquecido de encher o tanque."},{"en":"After I had been stuck for an hour, someone started the elevator again.","pt":"Depois de ficar preso por uma hora, alguém ligou o elevador de novo."}]},{"page":31,"unit":5,"topic":"Noun Phrases Containing Relative Clauses","ex":[{"en":"One thing (that) I'd really miss is hanging out with my friends.","pt":"Uma coisa de que eu sentiria muita falta é sair com meus amigos."},{"en":"The people (who/that) I'd miss the most are my parents.","pt":"As pessoas de quem eu mais sentiria falta são meus pais."},{"en":"Trying new foods is something I'd be very enthusiastic about.","pt":"Experimentar comidas novas é algo que me deixaria muito animado."},{"en":"Speaking a foreign language is something I'd be anxious about.","pt":"Falar uma língua estrangeira é algo que me deixaria ansioso."}]},{"page":33,"unit":5,"topic":"Expectations","ex":[{"en":"If you want to bring others, you're expected to ask if it's OK first.","pt":"Se quiser levar outras pessoas, espera-se que você pergunte antes."},{"en":"You're supposed to check with the host.","pt":"Você deve confirmar com o anfitrião."},{"en":"It's not acceptable to bring them without asking.","pt":"Não é aceitável levá-los sem perguntar."},{"en":"When someone sends you a gift, you're expected to thank the person.","pt":"Quando alguém te manda um presente, espera-se que você agradeça."}]},{"page":37,"unit":6,"topic":"Describing Problems 1","ex":[{"en":"The suitcase lining is torn. / It has a tear in it.","pt":"O forro da mala está rasgado. / Tem um rasgo nele."},{"en":"My pants are stained. / They have a stain on them.","pt":"Minha calça está manchada. / Tem uma mancha nela."},{"en":"The camera lens is scratched. / There are a few scratches on it.","pt":"A lente da câmera está arranhada. / Há alguns arranhões nela."},{"en":"The car is damaged. / There is some damage on the bumper.","pt":"O carro está danificado. / Há algum dano no para-choque."}]},{"page":39,"unit":6,"topic":"Describing Problems 2","ex":[{"en":"The alarm needs fixing. / It needs to be fixed.","pt":"O alarme precisa de conserto. / Precisa ser consertado."},{"en":"The cupboards need cleaning. / They need to be cleaned.","pt":"Os armários precisam de limpeza. / Precisam ser limpos."},{"en":"Everything keeps burning.","pt":"Tudo fica queimando."},{"en":"My phone keeps dropping calls.","pt":"Meu telefone fica derrubando as ligações."}]},{"page":45,"unit":7,"topic":"Passive with Prepositions","ex":[{"en":"Our city streets are being damaged as a result of heavy traffic.","pt":"Nossas ruas estão sendo danificadas em consequência do trânsito intenso."},{"en":"The roads aren't being repaired due to a lack of funding.","pt":"As estradas não estão sendo consertadas por falta de verba."},{"en":"Climate changes are being caused by high emissions of carbon dioxide.","pt":"As mudanças climáticas estão sendo causadas por altas emissões de CO2."},{"en":"Many public parks have been lost through overbuilding.","pt":"Muitos parques públicos foram perdidos por causa da construção excessiva."}]},{"page":47,"unit":7,"topic":"Infinitive Clauses and Phrases","ex":[{"en":"Another way to stop them is to get a news station to run a story.","pt":"Outra forma de detê-los é conseguir que um canal publique uma matéria."},{"en":"The best way to fight poverty is to provide education to all children.","pt":"A melhor forma de combater a pobreza é dar educação a todas as crianças."},{"en":"One way to reduce unemployment is to create more jobs.","pt":"Uma forma de reduzir o desemprego é criar mais empregos."},{"en":"One way to improve air quality is to increase the use of cleaner energy.","pt":"Uma forma de melhorar a qualidade do ar é aumentar o uso de energia limpa."}]},{"page":51,"unit":8,"topic":"Would Rather and Would Prefer","ex":[{"en":"Would you rather take an art course or a professional course?","pt":"Você prefere fazer um curso de arte ou um curso profissional?"},{"en":"I'd rather not take either.","pt":"Eu prefiro não fazer nenhum dos dois."},{"en":"I'd prefer not to join a group.","pt":"Eu prefiro não entrar num grupo."},{"en":"I'd definitely rather have a job where I'm outdoors.","pt":"Eu com certeza prefiro um emprego em que eu fique ao ar livre."}]},{"page":53,"unit":8,"topic":"By + Gerund to Describe How to Do Things","ex":[{"en":"I learn new words best by writing them down and reviewing them many times.","pt":"Aprendo palavras novas melhor anotando-as e revisando muitas vezes."},{"en":"Students can become better writers by reading more.","pt":"Os alunos podem se tornar melhores escritores lendo mais."},{"en":"You can improve your accent by listening to songs and singing along.","pt":"Você pode melhorar seu sotaque ouvindo músicas e cantando junto."},{"en":"A good way to memorize new vocabulary is by playing vocabulary games.","pt":"Uma boa forma de memorizar vocabulário novo é jogando jogos de vocabulário."}]},{"page":59,"unit":9,"topic":"Get or Have Something Done","ex":[{"en":"They got the sink fixed.","pt":"Eles mandaram consertar a pia."},{"en":"Did you have your bedroom painted?","pt":"Você mandou pintar seu quarto?"},{"en":"I didn't repair my own laptop. I got it fixed at the electronics store.","pt":"Não consertei meu notebook. Mandei consertar na loja de eletrônicos."},{"en":"Jessica is having her nails done.","pt":"A Jessica está fazendo as unhas — alguém faz para ela."}]},{"page":61,"unit":9,"topic":"Making Suggestions","ex":[{"en":"What about joining a running club?","pt":"Que tal entrar num clube de corrida?"},{"en":"Have you thought about asking your friends to introduce you around?","pt":"Você já pensou em pedir aos amigos para te apresentarem às pessoas?"},{"en":"One option is to join a club.","pt":"Uma opção é entrar num clube."},{"en":"It might be a good idea to check out the cultural events at the university.","pt":"Pode ser uma boa ideia conferir os eventos culturais da universidade."}]},{"page":65,"unit":10,"topic":"Referring to Time in the Past","ex":[{"en":"The Olympic Games originated about 3,000 years ago.","pt":"Os Jogos Olímpicos surgiram há cerca de 3.000 anos."},{"en":"During the 1970s, the first video game console was released.","pt":"Durante os anos 1970, o primeiro console de videogame foi lançado."},{"en":"The Beatles were together from 1960 to 1970.","pt":"Os Beatles ficaram juntos de 1960 a 1970."},{"en":"Women have competed in the Olympics since 1900.","pt":"As mulheres competem nas Olimpíadas desde 1900."}]},{"page":67,"unit":10,"topic":"Predicting the Future with Will","ex":[{"en":"We won't have colonies on Mars.","pt":"Não teremos colônias em Marte."},{"en":"In the future, most of the population will be living in cities.","pt":"No futuro, a maior parte da população estará vivendo em cidades."},{"en":"Within 50 years, we will have set up a research center on Mars.","pt":"Em até 50 anos, teremos montado um centro de pesquisa em Marte."},{"en":"Soon, computers will become more intelligent than humans.","pt":"Em breve, os computadores se tornarão mais inteligentes que os humanos."}]},{"page":73,"unit":11,"topic":"Time Clauses","ex":[{"en":"Before I graduated from high school, I had never worked.","pt":"Antes de me formar no ensino médio, eu nunca tinha trabalhado."},{"en":"Once I moved away from home, I learned to take care of myself.","pt":"Assim que saí de casa, aprendi a cuidar de mim mesmo."},{"en":"As soon as I got my own bank account, I started to be more responsible.","pt":"Assim que abri minha conta bancária, comecei a ser mais responsável."},{"en":"Until I moved to Alaska, I had never been away from home.","pt":"Até eu me mudar para o Alasca, eu nunca tinha saído de casa."}]},{"page":75,"unit":11,"topic":"Expressing Regret and Hypothetical Situations","ex":[{"en":"I shouldn't have taken out a student loan to pay for college.","pt":"Eu não deveria ter feito um empréstimo estudantil para pagar a faculdade."},{"en":"If I'd been more ambitious in college, I could have learned another language.","pt":"Se eu tivesse sido mais ambicioso na faculdade, poderia ter aprendido outro idioma."},{"en":"If I hadn't wasted so much money, I would have saved enough for grad school.","pt":"Se eu não tivesse desperdiçado tanto dinheiro, teria juntado o suficiente para a pós."},{"en":"I should have stayed in touch with my school friends.","pt":"Eu deveria ter mantido contato com meus amigos de escola."}]},{"page":79,"unit":12,"topic":"Describing Purpose","ex":[{"en":"(In order) to finance a new business, it's a good idea to get a bank loan.","pt":"Para financiar um novo negócio, é uma boa ideia conseguir um empréstimo."},{"en":"For an app to succeed, it has to be easy to use.","pt":"Para um aplicativo ter sucesso, ele precisa ser fácil de usar."},{"en":"To run a popular convenience store, you need to choose the right location.","pt":"Para administrar uma loja de conveniência popular, é preciso escolher o ponto certo."},{"en":"For a restaurant to attract more customers, it's important to understand their needs.","pt":"Para um restaurante atrair mais clientes, é importante entender as necessidades deles."}]},{"page":81,"unit":12,"topic":"Giving Reasons","ex":[{"en":"Since it's always so packed, there's a long wait outside the club.","pt":"Como vive lotado, há uma longa espera na entrada do clube."},{"en":"The Firefly is famous for its fantastic music.","pt":"O Firefly é famoso pela sua música fantástica."},{"en":"Due to the crowds, the Dizzy Lizard is difficult to get into.","pt":"Por causa da multidão, é difícil entrar no Dizzy Lizard."},{"en":"Samsung is a successful company due to its high investment in research.","pt":"A Samsung é uma empresa de sucesso por causa do alto investimento em pesquisa."}]},{"page":87,"unit":13,"topic":"Past Modals for Degrees of Certainty","ex":[{"en":"He must not have heard the doorbell.","pt":"Ele deve não ter ouvido a campainha."},{"en":"She may have just come back from vacation.","pt":"Ela talvez tenha acabado de voltar de férias."},{"en":"He could have had an emergency.","pt":"Ele pode ter tido uma emergência."},{"en":"She must have gotten fired.","pt":"Ela deve ter sido demitida."}]},{"page":89,"unit":13,"topic":"Past Modals for Judgments and Suggestions","ex":[{"en":"He shouldn't have used your car.","pt":"Ele não deveria ter usado seu carro."},{"en":"I would have asked them to help clean up the place.","pt":"Eu teria pedido que eles ajudassem a arrumar o lugar."},{"en":"I wouldn't have invited them to spend the weekend.","pt":"Eu não teria convidado eles para passar o fim de semana."},{"en":"She shouldn't have asked for such a personal favor in the first place.","pt":"Ela nem deveria ter pedido um favor tão pessoal, para começar."}]},{"page":93,"unit":14,"topic":"The Passive to Describe Process","ex":[{"en":"Many drawings are presented.","pt":"Muitos desenhos são apresentados."},{"en":"The drawings might be changed 10 times.","pt":"Os desenhos podem ser alterados 10 vezes."},{"en":"First, storyboards are drawn by story artists.","pt":"Primeiro, os storyboards são desenhados pelos artistas."},{"en":"Finally, the best recording is chosen for the final movie.","pt":"Por fim, a melhor gravação é escolhida para o filme final."}]},{"page":96,"unit":14,"topic":"Defining and Non-Defining Relative Clauses","ex":[{"en":"The art editor who creates the look of a magazine should make it attractive. (D)","pt":"O editor de arte que cria o visual da revista deve deixá-la atraente."},{"en":"The extras are the people who appear in the background scenes. (D)","pt":"Os figurantes são as pessoas que aparecem nas cenas de fundo."},{"en":"A game designer, who creates new games, works closely with the programmers. (ND)","pt":"Um designer de jogos, que cria novos jogos, trabalha junto com os programadores."},{"en":"A news reporter, who should be impartial, collects information about events. (ND)","pt":"Um repórter, que deve ser imparcial, coleta informações sobre os fatos."}]},{"page":101,"unit":15,"topic":"Giving Recommendations and Opinions","ex":[{"en":"Pet owners shouldn't be allowed to walk dogs without a leash.","pt":"Donos de pets não deveriam poder passear com cães sem coleira."},{"en":"Riding a bike on the sidewalk mustn't be permitted.","pt":"Andar de bicicleta na calçada não pode ser permitido."},{"en":"A rule has to be made to require bike lanes on city streets.","pt":"Uma regra precisa ser criada para exigir ciclovias nas ruas."},{"en":"Something has got to be done to stop littering.","pt":"Algo tem que ser feito para acabar com o lixo jogado na rua."}]},{"page":103,"unit":15,"topic":"Tag Questions for Opinions","ex":[{"en":"There are lots of clubs around, aren't there?","pt":"Tem um monte de clubes por aí, não tem?"},{"en":"Her neighbors don't make much noise, do they?","pt":"Os vizinhos dela não fazem muito barulho, fazem?"},{"en":"The city should provide child care, shouldn't it?","pt":"A cidade deveria oferecer creche, não deveria?"},{"en":"You can't sleep because of the noise, can you?","pt":"Você não consegue dormir por causa do barulho, consegue?"}]},{"page":107,"unit":16,"topic":"Talking About Past Accomplishments","ex":[{"en":"I didn't manage to get good grades in school.","pt":"Não consegui tirar boas notas na escola."},{"en":"I was able to finish the marathon last year.","pt":"Consegui terminar a maratona ano passado."},{"en":"I haven't managed to record an album yet.","pt":"Ainda não consegui gravar um álbum."},{"en":"I've been able to help kids achieve their goals.","pt":"Tenho conseguido ajudar crianças a alcançar seus objetivos."}]},{"page":109,"unit":16,"topic":"Describing Goals and Possible Future Accomplishments","ex":[{"en":"I hope I'll have seen more of the world.","pt":"Espero ter conhecido mais do mundo."},{"en":"What would you like to have achieved?","pt":"O que você gostaria de ter alcançado?"},{"en":"By this time next year, I hope I'll have finished my English course.","pt":"Até esta época no ano que vem, espero ter terminado meu curso de inglês."},{"en":"I'd like to have spent some time in an English-speaking country.","pt":"Eu gostaria de ter passado um tempo num país de língua inglesa."}]}],"evolve5":[{"page":3,"unit":null,"topic":"Present Habits","ex":[{"en":"She usually likes things the way they are. (rotina geral)","pt":"Ela geralmente gosta das coisas como estão."},{"en":"I tend to adapt to new situations quickly. (tendência)","pt":"Eu costumo me adaptar rapidamente a situações novas."},{"en":"I'll often call my parents when I want advice. (frequência)","pt":"Eu costumo ligar para meus pais quando quero um conselho."},{"en":"I usually listen to music when I'm cooking. (hábitos simultâneos)","pt":"Eu geralmente ouço música enquanto cozinho."},{"en":"I'm always worrying about my work. (hábito incômodo)","pt":"Eu vivo me preocupando com o meu trabalho."}]},{"page":5,"unit":null,"topic":"Past Habits","ex":[{"en":"We didn't use to make video calls, but we do now.","pt":"Não fazíamos chamadas de vídeo, mas agora fazemos."},{"en":"They never used to ride their bikes to school.","pt":"Eles nunca iam de bicicleta para a escola."},{"en":"On weekends, he would let me watch his TV.","pt":"Nos fins de semana, ele me deixava assistir à TV dele."},{"en":"I had a big bedroom when I was young. (estado — só used to / simple past)","pt":"Eu tinha um quarto grande quando era criança."},{"en":"I watched three shows last night. (ação única — só simple past)","pt":"Assisti a três programas ontem à noite."}]},{"page":13,"unit":null,"topic":"Comparative Structures","ex":[{"en":"The new project will require fewer resources and less time.","pt":"O novo projeto exigirá menos recursos e menos tempo."},{"en":"I prefer to study the ocean rather than learn about space.","pt":"Prefiro estudar o oceano a aprender sobre o espaço."},{"en":"I know less about Venus than about Mars.","pt":"Eu sei menos sobre Vênus do que sobre Marte."},{"en":"Technology is not advanced enough to send people to Mars.","pt":"A tecnologia não é avançada o suficiente para enviar pessoas a Marte."},{"en":"It's easier to use a tablet than to use a laptop.","pt":"É mais fácil usar um tablet do que um laptop."}]},{"page":15,"unit":null,"topic":"Superlative Structures and Ungradable Adjectives","ex":[{"en":"This country has some of the highest mountains in the world.","pt":"Este país tem algumas das montanhas mais altas do mundo."},{"en":"May is the best time to hike here.","pt":"Maio é a melhor época para fazer trilha aqui."},{"en":"It's the most fascinating place I've ever visited.","pt":"É o lugar mais fascinante que já visitei."},{"en":"The green parrots are totally amazing. (não-graduável + intensificador)","pt":"Os papagaios verdes são totalmente incríveis."},{"en":"My friends were absolutely furious.","pt":"Meus amigos estavam absolutamente furiosos."}]},{"page":23,"unit":null,"topic":"Relative Pronouns and Reduced Relative Clauses","ex":[{"en":"My sister, whose children I take care of, lives next door.","pt":"Minha irmã, de quem cuido dos filhos, mora ao lado."},{"en":"Today is the day when we decide it's time for a change.","pt":"Hoje é o dia em que decidimos que é hora de mudar."},{"en":"People worried about meeting strangers get nervous at parties.","pt":"Pessoas preocupadas em conhecer estranhos ficam nervosas em festas."},{"en":"The bus parked in front of the office is the one we'll take.","pt":"O ônibus estacionado em frente ao escritório é o que vamos pegar."},{"en":"Steven, a quick learner, adapts easily to new situations.","pt":"Steven, que aprende rápido, se adapta facilmente a situações novas."}]},{"page":25,"unit":null,"topic":"Present Participles","ex":[{"en":"The mall is full of people shopping for the holidays.","pt":"O shopping está cheio de gente comprando para as festas."},{"en":"We're standing in line waiting to check in for our flight.","pt":"Estamos na fila esperando para fazer o check-in do voo."},{"en":"There are a lot of fans waiting outside the stadium.","pt":"Há muitos fãs esperando do lado de fora do estádio."},{"en":"I love to stand on the hill looking down at the valley.","pt":"Adoro ficar na colina olhando o vale lá embaixo."},{"en":"The storm will affect people living in the South.","pt":"A tempestade vai afetar as pessoas que moram no Sul."}]},{"page":35,"unit":null,"topic":"Adding Emphasis","ex":[{"en":"It was such a big decision to move to Canada.","pt":"Foi uma decisão tão grande mudar para o Canadá."},{"en":"She is so ambitious that she has decided to work toward a PhD.","pt":"Ela é tão ambiciosa que decidiu fazer um doutorado."},{"en":"Everyone was on time, even Joseph, who is usually late.","pt":"Todos chegaram na hora, até o Joseph, que costuma se atrasar."},{"en":"It was time to leave, but they had only packed one suitcase.","pt":"Era hora de sair, mas eles tinham arrumado só uma mala."},{"en":"He demonstrated such talent that they hired him immediately.","pt":"Ele mostrou tanto talento que o contrataram na hora."}]},{"page":37,"unit":null,"topic":"Reflexive Pronouns and Other Another","ex":[{"en":"I enjoyed myself at the party.","pt":"Eu me diverti na festa."},{"en":"The employees themselves decide what time they start work.","pt":"Os próprios funcionários decidem a que horas começam a trabalhar."},{"en":"I can't lift this box by myself.","pt":"Não consigo levantar esta caixa sozinho."},{"en":"Some people drink coffee. Others prefer tea.","pt":"Algumas pessoas tomam café. Outras preferem chá."},{"en":"During exams, students are not allowed to help each other.","pt":"Durante as provas, os alunos não podem ajudar uns aos outros."}]},{"page":45,"unit":null,"topic":"Real Conditionals","ex":[{"en":"I feel nervous whenever I think about flying.","pt":"Fico nervoso sempre que penso em voar."},{"en":"If you try the therapy, it will make you more confident.","pt":"Se você experimentar a terapia, ela te deixará mais confiante."},{"en":"When I arrive at the airport, I will call you right away.","pt":"Quando eu chegar ao aeroporto, te ligo na hora."},{"en":"Everyone must take off their shoes if they want to enter.","pt":"Todos devem tirar os sapatos se quiserem entrar."},{"en":"Whenever I face my fear of heights, I have to cross that bridge.","pt":"Sempre que enfrento meu medo de altura, tenho que atravessar aquela ponte."}]},{"page":47,"unit":null,"topic":"Conditionals Alternatives to If","ex":[{"en":"Even if we meet in person, we may not reach an agreement.","pt":"Mesmo que nos encontremos pessoalmente, podemos não chegar a um acordo."},{"en":"I'm willing to try virtual meetings providing the technology is reliable.","pt":"Estou disposto a tentar reuniões virtuais, desde que a tecnologia seja confiável."},{"en":"We'll leave at 3:00 provided everyone is ready.","pt":"Vamos sair às 3h, desde que todos estejam prontos."},{"en":"You shouldn't study late unless it's absolutely necessary.","pt":"Você não deveria estudar até tarde, a não ser que seja absolutamente necessário."},{"en":"As long as the company makes a profit, the boss is happy.","pt":"Desde que a empresa dê lucro, o chefe fica feliz."}]},{"page":55,"unit":null,"topic":"Narrative Tenses","ex":[{"en":"He became famous when he was only 14.","pt":"Ele ficou famoso quando tinha apenas 14 anos."},{"en":"She translated what the president was saying.","pt":"Ela traduziu o que o presidente estava dizendo."},{"en":"All my friends went to the concert, but I'd forgotten to buy a ticket.","pt":"Todos os meus amigos foram ao show, mas eu tinha esquecido de comprar ingresso."},{"en":"The band had been playing all night, so they were very tired.","pt":"A banda tinha tocado a noite toda, então estavam muito cansados."},{"en":"We were exhausted when we reached the town.","pt":"Estávamos exaustos quando chegamos à cidade."}]},{"page":57,"unit":null,"topic":"Reported Speech with Modal Verbs","ex":[{"en":"\"We won't study space next week.\" →","pt":""},{"en":"\"Everyone should study for the test.\" →","pt":""},{"en":"\"We may not have time.\" → Lisa explained that we might not have time.","pt":"A Lisa explicou que talvez não tivéssemos tempo."},{"en":"\"When will you finish?\" → My boss asked me when I would finish.","pt":"Meu chefe me perguntou quando eu terminaria."},{"en":"\"I can play the piano well.\" → I said I could play the piano well.","pt":"Eu disse que sabia tocar piano bem."}]},{"page":67,"unit":null,"topic":"Gerunds and Infinitives after Adjectives Nouns Pronouns","ex":[{"en":"It's boring and difficult to work at night.","pt":"É chato e difícil trabalhar à noite."},{"en":"It was an interesting place to visit.","pt":"Era um lugar interessante para visitar."},{"en":"I need something to eat.","pt":"Preciso de algo para comer."},{"en":"It was boring waiting in line for the roller coaster.","pt":"Foi chato esperar na fila da montanha-russa."},{"en":"I spend a lot of time traveling for my job.","pt":"Passo muito tempo viajando a trabalho."}]},{"page":69,"unit":null,"topic":"Infinitives after Verbs with and without Objects","ex":[{"en":"They agreed not to climb the mountain without an instructor.","pt":"Eles concordaram em não escalar a montanha sem um instrutor."},{"en":"He did not convince us to hire him.","pt":"Ele não nos convenceu a contratá-lo."},{"en":"My parents advised me to save money.","pt":"Meus pais me aconselharam a economizar dinheiro."},{"en":"I'd like to buy the lamp. (eu compro)","pt":"Eu gostaria de comprar o abajur."},{"en":"I'd like you to buy that lamp. (você compra)","pt":"Eu gostaria que você comprasse aquele abajur."}]},{"page":77,"unit":null,"topic":"Modal Like Expressions with Be","ex":[{"en":"If you drop that glass, it's bound to break.","pt":"Se você derrubar esse copo, ele com certeza vai quebrar."},{"en":"There's a lot of traffic, so we're likely to be late.","pt":"Há muito trânsito, então é provável que cheguemos atrasados."},{"en":"My mom was supposed to pick me up at 3:30, but she didn't.","pt":"Minha mãe deveria me buscar às 15h30, mas não veio."},{"en":"Quick, turn on the TV. The game is about to start.","pt":"Rápido, ligue a TV. O jogo está prestes a começar."},{"en":"Everyone who travels by plane is required to have a passport.","pt":"Todos que viajam de avião são obrigados a ter passaporte."}]},{"page":79,"unit":null,"topic":"Future Forms","ex":[{"en":"I'm meeting my friends tomorrow at 6:00 p.m. (plano definido)","pt":"Vou encontrar meus amigos amanhã às 18h."},{"en":"It's going to be a big surprise for them. (previsão)","pt":"Vai ser uma grande surpresa para eles."},{"en":"I might start my own business one day. (incerteza)","pt":"Talvez eu abra meu próprio negócio um dia."},{"en":"That looks difficult. I'll help you with it. (decisão no momento)","pt":"Isso parece difícil. Eu te ajudo com isso."},{"en":"In a few years, I'll be looking for a job. (ação em progresso no futuro)","pt":"Daqui a alguns anos, estarei procurando emprego."}]},{"page":87,"unit":null,"topic":"Unreal Conditionals","ex":[{"en":"If we got tickets to the concert, we wouldn't watch it on TV.","pt":"Se conseguíssemos ingressos para o show, não o assistiríamos pela TV."},{"en":"If Josh was studying at the library, I could help him.","pt":"Se o Josh estivesse estudando na biblioteca, eu poderia ajudá-lo."},{"en":"I could have been an X-ray technician if I had studied medicine.","pt":"Eu poderia ter sido técnico de raio-x se tivesse estudado medicina."},{"en":"I would have a nicer apartment if I hadn't bought a new car.","pt":"Eu teria um apartamento melhor se não tivesse comprado um carro novo."},{"en":"If they could work fewer hours, they wouldn't be so tired.","pt":"Se pudessem trabalhar menos horas, não estariam tão cansados."}]},{"page":89,"unit":null,"topic":"Wishes and Regrets","ex":[{"en":"I wish it was ten degrees cooler.","pt":"Eu queria que estivesse dez graus mais frio."},{"en":"If only we could buy some cold sodas.","pt":"Quem dera pudéssemos comprar uns refrigerantes gelados."},{"en":"I wish I had put the bottle in the refrigerator last night.","pt":"Eu queria ter colocado a garrafa na geladeira ontem à noite."},{"en":"Right now, I wish I was in a refrigerator!","pt":"Neste momento, eu queria estar dentro de uma geladeira!"},{"en":"If only the air conditioning hadn't broken!","pt":"Quem dera o ar-condicionado não tivesse quebrado!"}]},{"page":99,"unit":null,"topic":"Gerunds after Prepositions","ex":[{"en":"Josh boasted about buying a new car.","pt":"O Josh se gabou de ter comprado um carro novo."},{"en":"We are guilty of spending too much time on social media.","pt":"Somos culpados de passar tempo demais nas redes sociais."},{"en":"My fear of flying has stopped me from visiting you.","pt":"Meu medo de voar me impediu de te visitar."},{"en":"Mia often complains about working on the weekends.","pt":"A Mia vive reclamando de trabalhar nos fins de semana."},{"en":"You need to concentrate on developing your plan.","pt":"Você precisa se concentrar em desenvolver o seu plano."}]},{"page":101,"unit":null,"topic":"Causative Verbs","ex":[{"en":"My parents make me save money for my future.","pt":"Meus pais me fazem economizar dinheiro para o futuro."},{"en":"Surveys enable stores to estimate sales.","pt":"Pesquisas permitem que as lojas estimem as vendas."},{"en":"Her advice kept me from losing my job.","pt":"O conselho dela me impediu de perder o emprego."},{"en":"Customer feedback frequently makes us improve our products.","pt":"O feedback dos clientes frequentemente nos faz melhorar nossos produtos."},{"en":"Having my own home has enabled me to be independent.","pt":"Ter minha própria casa me permitiu ser independente."}]},{"page":109,"unit":null,"topic":"Passive Forms","ex":[{"en":"These products are usually imported. (simple present)","pt":"Esses produtos geralmente são importados."},{"en":"Were you given a refund? (simple past)","pt":"Você recebeu um reembolso?"},{"en":"The order has been canceled. (present perfect)","pt":"O pedido foi cancelado."},{"en":"The goods will be checked before they're shipped. (future)","pt":"As mercadorias serão verificadas antes de serem enviadas."},{"en":"Traders are now being watched more carefully. (present continuous)","pt":"Os comerciantes estão sendo vigiados mais de perto agora."}]},{"page":111,"unit":null,"topic":"Passives with Modals and Passive Infinitives","ex":[{"en":"Should the photos be taken in natural light?","pt":"As fotos deveriam ser tiradas com luz natural?"},{"en":"Good journalists don't need to be told what to do.","pt":"Bons jornalistas não precisam que lhes digam o que fazer."},{"en":"The facts must be checked by the editor.","pt":"Os fatos devem ser verificados pelo editor."},{"en":"The journalists refused to be told what to write.","pt":"Os jornalistas se recusaram a receber ordens sobre o que escrever."},{"en":"That photo of me had better be removed from your post.","pt":"É melhor essa foto minha ser removida da sua publicação."}]},{"page":119,"unit":null,"topic":"Adverbs with Adjectives and Adverbs","ex":[{"en":"John is especially skilled at painting.","pt":"O John é especialmente habilidoso em pintura."},{"en":"Sandra is artistically talented in many ways.","pt":"A Sandra é artisticamente talentosa de várias formas."},{"en":"Some people are able to learn languages particularly easily.","pt":"Algumas pessoas conseguem aprender idiomas com uma facilidade especial."},{"en":"My accountant always gives me financially correct information.","pt":"Meu contador sempre me dá informações financeiramente corretas."},{"en":"Natasha's house is full of artistically beautiful objects.","pt":"A casa da Natasha está cheia de objetos artisticamente belos."}]},{"page":121,"unit":null,"topic":"Making Non Count Nouns Countable","ex":[{"en":"A little bit of kindness brightens up people's lives.","pt":"Um pouquinho de gentileza ilumina a vida das pessoas."},{"en":"This is a useful piece of information.","pt":"Esta é uma informação útil."},{"en":"We played a few games of basketball over the weekend.","pt":"Jogamos algumas partidas de basquete no fim de semana."},{"en":"At the café, we ordered two cups of coffee and a glass of juice.","pt":"No café, pedimos duas xícaras de café e um copo de suco."},{"en":"Helping me move was an act of kindness.","pt":"Me ajudar na mudança foi um ato de gentileza."}]}],"evolve6":[{"page":3,"unit":null,"topic":"Commenting Adverbs with Future Forms","ex":[{"en":"Robots will undoubtedly ease the burden on social services.","pt":"Robôs sem dúvida vão aliviar a sobrecarga dos serviços sociais."},{"en":"Home health care is inevitably going to become a necessity.","pt":"O atendimento domiciliar inevitavelmente se tornará uma necessidade."},{"en":"Social services will certainly not replace human companionship.","pt":"Os serviços sociais certamente não substituirão a companhia humana."},{"en":"The robotics industry is definitely about to make life easier.","pt":"A indústria de robótica definitivamente está prestes a facilitar a vida."}]},{"page":5,"unit":null,"topic":"Future Perfect and Future Continuous","ex":[{"en":"By 2050, technology will have changed everything.","pt":"Até 2050, a tecnologia terá mudado tudo."},{"en":"Will they have taken over all helplines?","pt":"Eles terão assumido todas as centrais de atendimento?"},{"en":"This time tomorrow, I'll be flying to Hawaii.","pt":"A esta hora amanhã, estarei voando para o Havaí."},{"en":"We won't be having conversations with real people anymore.","pt":"Não estaremos mais conversando com pessoas reais."},{"en":"By the end of the semester, we will have covered the whole book.","pt":"Até o fim do semestre, teremos coberto o livro inteiro."}]},{"page":13,"unit":null,"topic":"Uses of Will","ex":[{"en":"Online quizzes will always give flattering results. (previsão)","pt":"Testes online sempre darão resultados lisonjeiros."},{"en":"My grandmother will always offer to make a cake. (hábito típico)","pt":"Minha avó sempre se oferece para fazer um bolo."},{"en":"I will never take another quiz like this! (decisão no momento)","pt":"Nunca mais farei um teste como esse!"},{"en":"He won't admit to his real motivation. (crítica de comportamento)","pt":"Ele não admite sua verdadeira motivação."},{"en":"We won't ever misuse your personal information. (promessa)","pt":"Nunca usaremos mal suas informações pessoais."}]},{"page":15,"unit":null,"topic":"Uses of Would","ex":[{"en":"When I was a kid, I would ride my bike everywhere. (hábito passado)","pt":"Quando era criança, eu andava de bicicleta por toda parte."},{"en":"Would you help me with these bags, please? (pedido educado)","pt":"Você poderia me ajudar com estas sacolas, por favor?"},{"en":"I would think he'd wear something nicer. (opinião educada)","pt":"Eu acharia que ele usaria algo mais elegante."},{"en":"He promised I would get the job. (discurso indireto)","pt":"Ele prometeu que eu conseguiria o emprego."},{"en":"The car wouldn't start, so I had to walk. (capacidade)","pt":"O carro não pegava, então tive que caminhar."}]},{"page":23,"unit":null,"topic":"Variations on Past Unreal Conditionals","ex":[{"en":"If you'd told me, I would have written it down.","pt":"Se você tivesse me dito, eu teria anotado."},{"en":"We would've missed the announcement if you hadn't been paying attention.","pt":"Teríamos perdido o aviso se você não estivesse prestando atenção."},{"en":"If you hadn't heard it, we would still be at the station.","pt":"Se você não tivesse ouvido, ainda estaríamos na estação."},{"en":"If you had been watching the children, Oliver wouldn't have a broken arm now.","pt":"Se você estivesse vigiando as crianças, o Oliver não estaria com o braço quebrado."},{"en":"If you hadn't heard the announcement, we would be waiting on the wrong platform.","pt":"Se você não tivesse ouvido o aviso, estaríamos esperando na plataforma errada."}]},{"page":25,"unit":null,"topic":"Commenting on the Past","ex":[{"en":"She may not have heard the full story. (cenário possível)","pt":"Ela pode não ter ouvido a história completa."},{"en":"You should have checked before taking the keys. (crítica)","pt":"Você deveria ter verificado antes de pegar as chaves."},{"en":"He could have been telling the truth. (ação em progresso possível)","pt":"Ele podia estar dizendo a verdade."},{"en":"They shouldn't have left the bike outside. (crítica de algo feito)","pt":"Eles não deveriam ter deixado a bicicleta lá fora."},{"en":"That information shouldn't have been shared with the public. (passiva)","pt":"Essa informação não deveria ter sido compartilhada com o público."}]},{"page":35,"unit":null,"topic":"Quantifiers and Prepositions in Relative Clauses","ex":[{"en":"I took hundreds of photos, most of which are really awful.","pt":"Tirei centenas de fotos, a maioria das quais é horrível."},{"en":"We invited a hundred guests, many of whom will stay at a hotel.","pt":"Convidamos cem pessoas, muitas das quais ficarão num hotel."},{"en":"The restaurant, the manager of which is my brother, is excellent.","pt":"O restaurante, cujo gerente é meu irmão, é excelente."},{"en":"This is the book about which I told you. (formal)","pt":"Este é o livro sobre o qual eu te falei."},{"en":"This is the book which I told you about. (informal)","pt":"Este é o livro do qual eu te falei."}]},{"page":37,"unit":null,"topic":"Noun Clauses with Question Words","ex":[{"en":"I didn't know why you wanted to see me.","pt":"Eu não sabia por que você queria me ver."},{"en":"How eyes adjust to light is fascinating.","pt":"Como os olhos se ajustam à luz é fascinante."},{"en":"What we see is a world of grays.","pt":"O que vemos é um mundo de tons de cinza."},{"en":"If I know where you're standing, I can find you on GPS.","pt":"Se eu souber onde você está, posso te achar no GPS."},{"en":"The man in the hat is not who the police are looking for.","pt":"O homem de chapéu não é quem a polícia procura."}]},{"page":45,"unit":null,"topic":"Participle Phrases in Initial Position","ex":[{"en":"Feeling overwhelmed by the crowd, he quickly made his way to the exit.","pt":"Sentindo-se sobrecarregado pela multidão, ele foi rápido para a saída."},{"en":"Having experienced the beauty of the sunset, she became determined to move.","pt":"Tendo vivido a beleza do pôr do sol, ela ficou decidida a se mudar."},{"en":"Convinced this was his last chance, John dropped everything.","pt":"Convencido de que era sua última chance, John largou tudo."},{"en":"Having finished college, I took a year off to travel.","pt":"Tendo terminado a faculdade, tirei um ano para viajar."},{"en":"Exhausted after a hard week, I decided to take it easy.","pt":"Exausto depois de uma semana difícil, decidi relaxar."}]},{"page":47,"unit":null,"topic":"Reduced Relative Clauses","ex":[{"en":"Tourists staying on the island need to book early.","pt":"Turistas hospedados na ilha precisam reservar cedo."},{"en":"Students interested in visiting the sites should sign up.","pt":"Alunos interessados em visitar os locais devem se inscrever."},{"en":"Areas surrounded by fences cannot be visited by the public.","pt":"Áreas cercadas por grades não podem ser visitadas pelo público."},{"en":"Requests from approved organizations will be given priority.","pt":"Pedidos de organizações aprovadas terão prioridade."},{"en":"I know a lot of people worried about their health.","pt":"Conheço muita gente preocupada com a saúde."}]},{"page":55,"unit":null,"topic":"Clefts","ex":[{"en":"What she wanted was a big party.","pt":"O que ela queria era uma grande festa."},{"en":"The only thing we wanted to do was dance.","pt":"A única coisa que queríamos fazer era dançar."},{"en":"It was my uncle who told me the good news.","pt":"Foi meu tio quem me deu a boa notícia."},{"en":"It wasn't until they brought out a cake that I realized the party was for me.","pt":"Só quando trouxeram o bolo é que percebi que a festa era para mim."},{"en":"The reason I love surprises is that life is usually predictable.","pt":"A razão de eu amar surpresas é que a vida costuma ser previsível."}]},{"page":57,"unit":null,"topic":"Question Words with Ever","ex":[{"en":"Whatever the critics say, I think it's a great movie.","pt":"Não importa o que os críticos digam, acho que é um ótimo filme."},{"en":"We'll get there, however long it takes.","pt":"Vamos chegar lá, não importa quanto tempo leve."},{"en":"Sleep wherever you like. There are lots of free rooms.","pt":"Durma onde quiser. Há vários quartos livres."},{"en":"Whoever told you that was lying. It's not true.","pt":"Quem quer que tenha dito isso estava mentindo. Não é verdade."},{"en":"Whenever we do to help, they always complain.","pt":"Não importa o que façamos para ajudar, eles sempre reclamam."}]},{"page":67,"unit":null,"topic":"Negative and Limiting Adverbials","ex":[{"en":"Never again will I take my family for granted.","pt":"Nunca mais vou menosprezar minha família."},{"en":"Only when everyone is paying attention am I starting the presentation.","pt":"Só quando todos estiverem atentos é que vou começar a apresentação."},{"en":"Not until then did I fully appreciate their importance.","pt":"Só então é que apreciei plenamente a importância deles."},{"en":"Little do they know what they're going to find.","pt":"Mal sabem eles o que vão encontrar."},{"en":"Hardly had we arrived when someone knocked at the door.","pt":"Mal tínhamos chegado quando alguém bateu à porta."}]},{"page":69,"unit":null,"topic":"Fronting Adverbials","ex":[{"en":"In the envelopes are crisp new dollar bills.","pt":"Dentro dos envelopes estão notas novinhas de dólar."},{"en":"On the table cloth lies a stack of red envelopes.","pt":"Sobre a toalha de mesa repousa uma pilha de envelopes vermelhos."},{"en":"From the kitchen wafts the smell of fresh dumplings.","pt":"Da cozinha vem o cheiro de dumplings fresquinhos."},{"en":"In the garden, she placed a ceramic frog near the door. (sem inversão)","pt":"No jardim, ela colocou um sapo de cerâmica perto da porta."},{"en":"Down the street walked an old man with a cane.","pt":"Pela rua descia um velho com uma bengala."}]},{"page":77,"unit":null,"topic":"Phrases with Get","ex":[{"en":"How can I get this paper finished with all the noise?","pt":"Como vou terminar este trabalho com todo esse barulho?"},{"en":"In the second act, the story gets very complicated.","pt":"No segundo ato, a história fica bem complicada."},{"en":"Coffee is the only thing that can get me moving in the morning.","pt":"Café é a única coisa que me faz funcionar de manhã."},{"en":"Our new sofa is getting delivered by the store this afternoon.","pt":"Nosso sofá novo será entregue pela loja hoje à tarde."},{"en":"We're going to get internet service installed on Tuesday.","pt":"Vamos mandar instalar a internet na terça-feira."}]},{"page":79,"unit":null,"topic":"Phrases with As","ex":[{"en":"Most people can tell the difference as instantly as experts can.","pt":"A maioria das pessoas percebe a diferença tão rápido quanto especialistas."},{"en":"He spoke as if he knew everything about the topic.","pt":"Ele falava como se soubesse tudo sobre o assunto."},{"en":"Fairy tales illustrate basic truths, such as honesty and courage.","pt":"Contos de fada ilustram verdades básicas, como honestidade e coragem."},{"en":"As a result of the survey, we changed our strategy.","pt":"Como resultado da pesquisa, mudamos nossa estratégia."},{"en":"She works as a translator for an international company.","pt":"Ela trabalha como tradutora numa empresa internacional."}]},{"page":87,"unit":null,"topic":"Referencing","ex":[{"en":"A sedentary lifestyle has side effects. It increases heart disease risk.","pt":"Um estilo de vida sedentário tem efeitos colaterais. Ele aumenta o risco cardíaco."},{"en":"Pedal desks help students focus on their studies.","pt":"Mesas com pedais ajudam os alunos a focar nos estudos deles."},{"en":"Schools give children active alternatives. Companies offer their workers the same.","pt":"Escolas dão alternativas ativas às crianças. Empresas oferecem o mesmo aos funcionários."},{"en":"She doesn't like it, but her parents do.","pt":"Ela não gosta disso, mas os pais dela gostam."},{"en":"They haven't tried it, but he has.","pt":"Eles não experimentaram, mas ele sim."}]},{"page":89,"unit":null,"topic":"Continuous Infinitives","ex":[{"en":"My daughter appears to be sleeping, but she isn't.","pt":"Minha filha parece estar dormindo, mas não está."},{"en":"The problem seems to be growing.","pt":"O problema parece estar crescendo."},{"en":"I need to be running five miles every day for the marathon.","pt":"Preciso estar correndo oito quilômetros por dia para a maratona."},{"en":"You're watching cat videos when you should be sleeping!","pt":"Você está vendo vídeos de gato quando deveria estar dormindo!"},{"en":"We're going to be looking at the flip side of the issue.","pt":"Vamos estar analisando o outro lado da questão."}]},{"page":99,"unit":null,"topic":"Simple Past for Unreal Situations","ex":[{"en":"If we had a more varied diet, we would reduce our negative effect.","pt":"Se tivéssemos uma dieta mais variada, reduziríamos nosso impacto negativo."},{"en":"I wish people were more careful about what they ate.","pt":"Eu queria que as pessoas tomassem mais cuidado com o que comem."},{"en":"My parents would rather we didn't eat red meat.","pt":"Meus pais preferiam que não comêssemos carne vermelha."},{"en":"Suppose we all stopped eating beef. What would we eat instead?","pt":"Suponha que todos parássemos de comer carne. O que comeríamos?"},{"en":"It's high time we expanded our diet to include insect proteins.","pt":"Já passou da hora de ampliarmos nossa dieta para incluir proteína de inseto."}]},{"page":101,"unit":null,"topic":"It Constructions","ex":[{"en":"It is said that renewable energy is our future.","pt":"Diz-se que a energia renovável é o nosso futuro."},{"en":"It has been argued that climate change increases hurricanes.","pt":"Argumenta-se que a mudança climática aumenta os furacões."},{"en":"It is reasonable to assume a connection between fossil fuels and warming.","pt":"É razoável supor uma conexão entre combustíveis fósseis e o aquecimento."},{"en":"It seems unlikely that social enterprises will replace energy companies.","pt":"Parece improvável que empresas sociais substituam as de energia."},{"en":"It could be a mistake to assume that this trend will continue.","pt":"Pode ser um erro supor que essa tendência vai continuar."}]},{"page":109,"unit":null,"topic":"Subject Verb Agreement","ex":[{"en":"The marketing department is located on the third floor. (foco no grupo)","pt":"O departamento de marketing fica no terceiro andar."},{"en":"Good news is always welcome.","pt":"Boa notícia é sempre bem-vinda."},{"en":"The media never admits when they're wrong.","pt":"A mídia nunca admite quando está errada."},{"en":"Everyone knows that red means stop.","pt":"Todo mundo sabe que vermelho significa parar."},{"en":"Either John or my parents are going to meet us at the station.","pt":"Ou o John ou meus pais vão nos encontrar na estação."}]},{"page":111,"unit":null,"topic":"Articles","ex":[{"en":"In U.S. weddings, it is common for the bride to wear white. (compartilhado)","pt":"Em casamentos nos EUA, é comum a noiva usar branco."},{"en":"This is the darkest shade of green I've ever seen. (superlativo)","pt":"Este é o tom de verde mais escuro que já vi."},{"en":"Color can evoke feelings and memories. (genérico, sem artigo)","pt":"A cor pode evocar sentimentos e memórias."},{"en":"He used a shade of orange that I've never seen before. (primeira menção)","pt":"Ele usou um tom de laranja que eu nunca tinha visto."},{"en":"I'd like to work as an interior decorator one day. (profissão)","pt":"Eu gostaria de trabalhar como decorador de interiores um dia."}]},{"page":119,"unit":null,"topic":"The Present Subjunctive","ex":[{"en":"He insists that we all be ready to go at noon.","pt":"Ele insiste que estejamos todos prontos para sair ao meio-dia."},{"en":"I suggest that you not come any earlier than two.","pt":"Sugiro que você não venha antes das duas."},{"en":"He recommended that we allow extra time for traffic.","pt":"Ele recomendou que reservássemos um tempo extra para o trânsito."},{"en":"It is imperative that he complete the application immediately.","pt":"É imperativo que ele preencha o formulário imediatamente."},{"en":"The officer's demand that we pull the car over was surprising.","pt":"A ordem do policial de que encostássemos o carro foi surpreendente."}]},{"page":121,"unit":null,"topic":"Perfect Infinitive","ex":[{"en":"The hanging gardens of Babylon are thought to have been built long ago.","pt":"Os jardins suspensos da Babilônia teriam sido construídos há muito tempo."},{"en":"We were relieved to have made it to the end of the trail before sunset.","pt":"Ficamos aliviados por ter chegado ao fim da trilha antes do pôr do sol."},{"en":"Based on the mess, her dinner party appears to have happened.","pt":"Pela bagunça, a janta dela parece ter mesmo acontecido."},{"en":"The mayor was shocked to have lost the election.","pt":"O prefeito ficou chocado por ter perdido a eleição."},{"en":"The residents might not have wanted to move, but they had to.","pt":"Os moradores talvez não quisessem se mudar, mas tiveram que."}]}]};
